{
  "name": "image-flow",
  "displayName": "Image Flow - AI 绘图",
  "version": "1.0.0",
  "description": "在 VS Code 编辑器内对 Markdown 文件调用 AI 绘图后端生成图片",
  "main": "./dist/extension.js",
  "engines": {
    "vscode": "^1.85.0"
  },
  "categories": ["Other"],
  "activationEvents": ["onStartupFinished"],
  "contributes": {
    "viewsContainers": {
      "activitybar": [
        {
          "id": "image-flow",
          "title": "AI 绘图",
          "icon": "$(image)"
        }
      ]
    },
    "views": {
      "image-flow": [
        {
          "type": "webview",
          "id": "image-flow.sidebar",
          "name": "AI 绘图"
        }
      ]
    },
    "commands": [
      {
        "command": "image-flow.generateImage",
        "title": "Image Flow: 生成 AI 图片"
      },
      {
        "command": "image-flow.previewRequest",
        "title": "Image Flow: 预览请求"
      }
    ],
    "menus": {
      "explorer/context": [
        {
          "command": "image-flow.generateImage",
          "when": "resourceExtname == .md"
        },
        {
          "command": "image-flow.previewRequest",
          "when": "resourceExtname == .md"
        }
      ],
      "editor/context": [
        {
          "command": "image-flow.generateImage",
          "when": "resourceExtname == .md"
        },
        {
          "command": "image-flow.previewRequest",
          "when": "resourceExtname == .md"
        }
      ]
    },
    "configuration": {
      "title": "Image Flow",
      "properties": {
        "imageFlow.apiKey": {
          "type": "string",
          "default": "",
          "description": "Grsai API Key"
        },
        "imageFlow.baseUrl": {
          "type": "string",
          "default": "https://grsai.dakka.com.cn",
          "enum": [
            "https://grsai.dakka.com.cn",
            "https://grsaiapi.com"
          ],
          "description": "API 节点地址"
        },
        "imageFlow.model": {
          "type": "string",
          "default": "nano-banana-2",
          "enum": [
            "nano-banana-2",
            "nano-banana-pro",
            "gpt-image-2",
            "gpt-image-2-vip"
          ],
          "description": "AI 模型"
        },
        "imageFlow.aspectRatio": {
          "type": "string",
          "default": "3:4",
          "enum": ["1:1", "16:9", "9:16", "4:3", "3:4"],
          "description": "图片比例"
        },
        "imageFlow.imageSize": {
          "type": "string",
          "default": "1K",
          "enum": ["1K", "2K", "4K"],
          "description": "图片分辨率"
        },
        "imageFlow.concurrency": {
          "type": "number",
          "default": 1,
          "minimum": 1,
          "maximum": 10,
          "description": "一次生成的并发张数"
        },
        "imageFlow.workbenchCols": {
          "type": "number",
          "default": 4,
          "minimum": 1,
          "maximum": 8,
          "description": "工作台素材缩略图每行张数"
        },
        "imageFlow.tasksCols": {
          "type": "number",
          "default": 2,
          "minimum": 1,
          "maximum": 8,
          "description": "任务页缩略图每行张数"
        },
        "imageFlow.modelInjections": {
          "type": "object",
          "default": {},
          "description": "模型注入提示词映射"
        }
      }
    }
  },
  "scripts": {
    "compile": "npm run check-types && npm run lint && node esbuild.config.mjs",
    "watch": "node esbuild.config.mjs --watch",
    "package": "npm run compile && npx @vscode/vsce package",
    "check-types": "tsc -p tsconfig.json --noEmit && tsc -p tsconfig.webview.json --noEmit",
    "lint": "eslint src/ media/",
    "test": "tsc -p tsconfig.test.json && npx vscode-test"
  },
  "dependencies": {
    "react": "^19.0.0",
    "react-dom": "^19.0.0",
    "@radix-ui/react-tabs": "^1.1.0",
    "@radix-ui/react-select": "^2.1.0",
    "@radix-ui/react-scroll-area": "^1.2.0"
  },
  "devDependencies": {
    "@types/mocha": "^10.0.0",
    "@types/node": "^22.0.0",
    "@types/react": "^19.0.0",
    "@types/react-dom": "^19.0.0",
    "@types/vscode": "^1.85.0",
    "@typescript-eslint/eslint-plugin": "^8.0.0",
    "@typescript-eslint/parser": "^8.0.0",
    "@vscode/test-cli": "^0.0.10",
    "@vscode/test-electron": "^2.4.0",
    "esbuild": "^0.25.0",
    "eslint": "^9.0.0",
    "mocha": "^11.0.0",
    "typescript": "^5.7.0"
  }
}

import * as esbuild from 'esbuild';

const isWatch = process.argv.includes('--watch');

/** @type {esbuild.BuildOptions} */
const extConfig = {
  entryPoints: ['src/extension.ts'],
  bundle: true,
  platform: 'node',
  target: 'node22',
  format: 'cjs',
  outfile: 'dist/extension.js',
  external: ['vscode'],
  sourcemap: true,
  minify: false,
};

/** @type {esbuild.BuildOptions} */
const sidebarConfig = {
  entryPoints: ['media/sidebar.tsx'],
  bundle: true,
  platform: 'browser',
  format: 'iife',
  outfile: 'media/sidebar.js',
  sourcemap: true,
  minify: false,
};

async function main() {
  if (isWatch) {
    const extCtx = await esbuild.context(extConfig);
    const sidebarCtx = await esbuild.context(sidebarConfig);
    await Promise.all([extCtx.watch(), sidebarCtx.watch()]);
    console.log('watching...');
  } else {
    await Promise.all([
      esbuild.build(extConfig),
      esbuild.build(sidebarConfig),
    ]);
    console.log('build complete');
  }
}

main().catch((e) => {
  console.error(e);
  process.exit(1);
});

import tseslint from '@typescript-eslint/eslint-plugin';
import tsparser from '@typescript-eslint/parser';

export default [
  {
    ignores: ['dist/**', 'out/**', 'media/sidebar.js', 'esbuild.config.mjs'],
  },
  {
    files: ['src/**/*.ts', 'media/**/*.tsx', 'media/**/*.ts', 'test/**/*.ts'],
    languageOptions: {
      parser: tsparser,
      parserOptions: {
        ecmaVersion: 2022,
        sourceType: 'module',
      },
    },
    plugins: {
      '@typescript-eslint': tseslint,
    },
    rules: {
      'no-unused-vars': 'off',
      '@typescript-eslint/no-unused-vars': ['warn', { argsIgnorePattern: '^_' }],
      'no-console': 'off',
      'semi': ['warn', 'always'],
      'quotes': ['warn', 'single', { avoidEscape: true }],
    },
  },
];

{
  "version": "0.2.0",
  "configurations": [
    {
      "name": "Run Extension",
      "type": "extensionHost",
      "request": "launch",
      "args": [
        "--extensionDevelopmentPath=${workspaceFolder}"
      ],
      "outFiles": [
        "${workspaceFolder}/dist/**/*.js"
      ],
      "preLaunchTask": "npm: compile"
    }
  ]
}

