/** 扩展与 Webview 共享类型，两端共用避免漂移 */

// --- Webview 消息协议 ---

export interface InitMsg {
  type: 'init';
}

export interface ConfigMsg {
  type: 'config';
  config: ExtensionConfig;
}

export interface ActiveMdMsg {
  type: 'activeMd';
  filePath: string | null;
  fileName: string | null;
}

export interface TasksMsg {
  type: 'tasks';
  tasks: TaskInfo[];
  history: HistoryEntry[];
}

export interface MaterialsMsg {
  type: 'materials';
  auto: MaterialLibrary[];
  manual: MaterialLibrary[];
}

export interface StatusMsg {
  type: 'status';
  message: string;
  isError: boolean;
}

export interface ProgressMsg {
  type: 'progress';
  taskId: string;
  jobs: JobState[];
  images: string[];
  errors: string[];
  startedAt: number;
}

export type ExtToWebview =
  | InitMsg
  | ConfigMsg
  | ActiveMdMsg
  | TasksMsg
  | MaterialsMsg
  | StatusMsg
  | ProgressMsg;

export interface GenerateMsg {
  type: 'generate';
}

export interface PreviewMsg {
  type: 'preview';
}

export interface SaveConfigMsg {
  type: 'saveConfig';
  key: string;
  value: unknown;
}

export interface SetApiKeyMsg {
  type: 'setApiKey';
  value: string;
}

export interface AddMaterialDirMsg {
  type: 'addMaterialDir';
}

export interface RemoveMaterialDirMsg {
  type: 'removeMaterialDir';
  dir: string;
}

export interface InsertImageMsg {
  type: 'insertImage';
  imagePath: string;
}

export interface OpenImageMsg {
  type: 'openImage';
  imagePath: string;
}

export interface OpenUrlMsg {
  type: 'openUrl';
  url: string;
}

export type WebviewToExt =
  | GenerateMsg
  | PreviewMsg
  | SaveConfigMsg
  | SetApiKeyMsg
  | AddMaterialDirMsg
  | RemoveMaterialDirMsg
  | InsertImageMsg
  | OpenImageMsg
  | OpenUrlMsg;

// --- 配置 ---

export interface ExtensionConfig {
  apiKey: string;
  baseUrl: string;
  model: string;
  aspectRatio: string;
  imageSize: string;
  concurrency: number;
  workbenchCols: number;
  tasksCols: number;
  modelInjections: Record<string, string>;
}

// --- 任务 ---

export type JobStatus = 'submitting' | 'running' | 'succeeded' | 'failed' | 'violation';

export interface JobState {
  index: number;
  id: string | null;
  status: JobStatus;
  progress: number;
  error: string | null;
  images: string[];
}

export interface TaskInfo {
  id: string;
  folderName: string;
  folderPath: string;
  mdFileName: string;
  model: string;
  jobs: JobState[];
  startedAt: number;
  sessionStart: number;
}

export interface HistoryEntry {
  folderName: string;
  folderPath: string;
  imageCount: number;
  images: string[];
}

// --- 素材库 ---

export interface MaterialLibrary {
  name: string;
  path: string;
  images: MaterialImage[];
}

export interface MaterialImage {
  path: string;
  name: string;
  webviewUri: string;
}

// --- 预设 ---

export const MODELS = ['nano-banana-2', 'nano-banana-pro', 'gpt-image-2', 'gpt-image-2-vip'] as const;

export const ASPECT_RATIOS = ['1:1', '16:9', '9:16', '4:3', '3:4'] as const;

export const IMAGE_SIZES = ['1K', '2K', '4K'] as const;

export const BASE_URLS = [
  { label: '国内节点', value: 'https://grsai.dakka.com.cn' },
  { label: '全球节点', value: 'https://grsaiapi.com' },
] as const;

/** gpt-image-2-vip 像素换算表: ratio+size → WxH */
export const VIP_PIXEL_MAP: Record<string, Record<string, string>> = {
  '1:1': { '1K': '1024x1024', '2K': '2048x2048', '4K': '4096x4096' },
  '16:9': { '1K': '1344x768', '2K': '2688x1536', '4K': '5376x3072' },
  '9:16': { '1K': '768x1344', '2K': '1536x2688', '4K': '3072x5376' },
  '4:3': { '1K': '1152x864', '2K': '2304x1728', '4K': '4608x3456' },
  '3:4': { '1K': '864x1152', '2K': '1728x2304', '4K': '3456x4608' },
};

/** 图片扩展名白名单 */
export const IMAGE_EXTENSIONS = ['png', 'jpg', 'jpeg', 'gif', 'webp', 'bmp', 'svg'];

/** 种子注入提示词 */
export const SEED_INJECTIONS: Record<string, string> = {
  'gpt-image-2': '整体画面弱化微小细节，避免过度刻画。',
  'gpt-image-2-vip': '整体画面弱化微小细节，避免过度刻画。',
};

/** 扩展名 → MIME 映射 */
export function extToMime(ext: string): string {
  const m: Record<string, string> = {
    png: 'image/png',
    jpg: 'image/jpeg',
    jpeg: 'image/jpeg',
    gif: 'image/gif',
    webp: 'image/webp',
    bmp: 'image/bmp',
    svg: 'image/svg+xml',
  };
  return m[ext] || 'image/png';
}

import * as vscode from 'vscode';
import { SEED_INJECTIONS, type ExtensionConfig } from './shared';

/** 配置管理：apiKey → secrets，其余 → globalState，素材库 → workspaceState */
export class ConfigManager {
  private secrets: vscode.SecretStorage;
  private globalState: vscode.Memento;
  private workspaceState: vscode.Memento;

  constructor(context: vscode.ExtensionContext) {
    this.secrets = context.secrets;
    this.globalState = context.globalState;
    this.workspaceState = context.workspaceState;
  }

  /** 首次激活种入 modelInjections 种子（不覆盖已有键） */
  async seedInjections(): Promise<void> {
    const stored = this.globalState.get<Record<string, string>>('modelInjections') || {};
    let changed = false;
    for (const [model, injection] of Object.entries(SEED_INJECTIONS)) {
      if (!(model in stored)) {
        stored[model] = injection;
        changed = true;
      }
    }
    if (changed) {
      await this.globalState.update('modelInjections', stored);
    }
  }

  async getApiKey(): Promise<string> {
    return (await this.secrets.get('apiKey')) || '';
  }

  async setApiKey(value: string): Promise<void> {
    await this.secrets.store('apiKey', value);
  }

  get<T>(key: string, defaultValue: T): T {
    return this.globalState.get<T>(key) ?? defaultValue;
  }

  async set(key: string, value: unknown): Promise<void> {
    await this.globalState.update(key, value);
  }

  async getConfig(): Promise<ExtensionConfig> {
    const cfg = vscode.workspace.getConfiguration('imageFlow');
    return {
      apiKey: await this.getApiKey(),
      baseUrl: this.get<string>('baseUrl', cfg.get<string>('baseUrl') || 'https://grsai.dakka.com.cn'),
      model: this.get<string>('model', cfg.get<string>('model') || 'nano-banana-2'),
      aspectRatio: this.get<string>('aspectRatio', cfg.get<string>('aspectRatio') || '3:4'),
      imageSize: this.get<string>('imageSize', cfg.get<string>('imageSize') || '1K'),
      concurrency: this.get<number>('concurrency', cfg.get<number>('concurrency') || 1),
      workbenchCols: this.get<number>('workbenchCols', cfg.get<number>('workbenchCols') || 4),
      tasksCols: this.get<number>('tasksCols', cfg.get<number>('tasksCols') || 2),
      modelInjections: this.get<Record<string, string>>('modelInjections', cfg.get<Record<string, string>>('modelInjections') || {}),
    };
  }

  /** 获取素材库列表 */
  getMaterialDirs(): string[] {
    return this.workspaceState.get<string[]>('materialDirs') || [];
  }

  async addMaterialDir(dir: string): Promise<void> {
    const dirs = this.getMaterialDirs();
    if (!dirs.includes(dir)) {
      dirs.push(dir);
      await this.workspaceState.update('materialDirs', dirs);
    }
  }

  async removeMaterialDir(dir: string): Promise<void> {
    let dirs = this.getMaterialDirs();
    dirs = dirs.filter((d) => d !== dir);
    await this.workspaceState.update('materialDirs', dirs);
  }
}

import * as path from 'path';
import * as fs from 'fs';

export interface RefImage {
  /** 编号（从 1 开始） */
  index: number;
  /** data URI */
  dataUri: string;
  /** 原始路径 */
  originalPath: string;
}

export interface ParseResult {
  /** 替换后的正文（图片语法替换为 [imageN]） */
  body: string;
  /** 去重编号的参考图列表 */
  refImages: RefImage[];
}

/**
 * 解析 Markdown 正文，提取参考图并替换为 [imageN]
 *
 * 匹配 `![alt](路径)` 与 `![alt](<路径>)`，
 * 按首次出现顺序去重编号。
 */
export function parseMarkdown(mdContent: string, mdDir: string): ParseResult {
  const imageRefs = new Map<string, number>(); // 路径 → 编号
  const refImages: RefImage[] = [];
  let nextIndex = 1;

  // 匹配 ![alt](路径) 或 ![alt](<路径>)
  const imgRegex = /!\[([^\]]*)\]\((?:<([^>]+)>|([^)\s]+))\)/g;

  const body = mdContent.replace(imgRegex, (fullMatch, alt, bracketedPath, plainPath) => {
    const rawPath = (bracketedPath || plainPath || '').trim();
    if (!rawPath) return fullMatch;

    if (imageRefs.has(rawPath)) {
      const idx = imageRefs.get(rawPath)!;
      return `[image${idx}](${path.basename(rawPath, path.extname(rawPath))})`;
    }

    const idx = nextIndex;
    imageRefs.set(rawPath, idx);
    nextIndex++;

    const absPath = path.resolve(mdDir, rawPath);
    const mime = mimeFromExt(path.extname(absPath).toLowerCase().replace('.', ''));
    const dataUri = fileToDataUri(absPath, mime);

    refImages.push({ index: idx, dataUri, originalPath: rawPath });

    return `[image${idx}](${path.basename(rawPath, path.extname(rawPath))})`;
  });

  return { body, refImages };
}

/** 读取文件并转为 data URI */
export function fileToDataUri(filePath: string, mime: string): string {
  const buffer = fs.readFileSync(filePath);
  const b64 = buffer.toString('base64');
  return `data:${mime};base64,${b64}`;
}

/** 根据扩展名推断 MIME */
export function mimeFromExt(ext: string): string {
  const m: Record<string, string> = {
    png: 'image/png',
    jpg: 'image/jpeg',
    jpeg: 'image/jpeg',
    gif: 'image/gif',
    webp: 'image/webp',
    bmp: 'image/bmp',
    svg: 'image/svg+xml',
  };
  return m[ext] || 'image/png';
}

/** 检查扩展名是否在图片白名单中 */
export function isImageExt(ext: string): boolean {
  const exts = ['png', 'jpg', 'jpeg', 'gif', 'webp', 'bmp', 'svg'];
  return exts.includes(ext.toLowerCase());
}

/** 从 URL 中提取文件扩展名 */
export function extFromUrl(url: string): string {
  try {
    const u = new URL(url);
    const basename = path.basename(u.pathname);
    // 去掉查询参数
    const clean = basename.split('?')[0];
    const ext = path.extname(clean).toLowerCase().replace('.', '');
    return ext;
  } catch {
    return '';
  }
}

import { VIP_PIXEL_MAP } from './shared';

export interface GenerateRequest {
  model: string;
  prompt: string;
  images: string[];
  aspectRatio: string;
  imageSize: string;
  replyType: 'async';
}

export interface GenerateResponse {
  id: string;
  status: 'running' | 'succeeded' | 'failed' | 'violation';
  results?: { url: string }[];
  progress?: number;
  error?: string;
}

const TIMEOUT_MS = 30_000;

/** 构建生成请求体，处理各模型尺寸字段差异 */
export function buildRequestBody(
  model: string,
  prompt: string,
  images: string[],
  aspectRatio: string,
  imageSize: string,
): GenerateRequest {
  const body: GenerateRequest = {
    model,
    prompt,
    images,
    aspectRatio: aspectRatio,
    imageSize,
    replyType: 'async',
  };

  if (model.startsWith('nano-banana')) {
    body.aspectRatio = aspectRatio;
    body.imageSize = imageSize;
  } else if (model === 'gpt-image-2') {
    body.aspectRatio = aspectRatio;
    delete (body as Record<string, unknown>).imageSize;
  } else if (model === 'gpt-image-2-vip') {
    const pixels = VIP_PIXEL_MAP[aspectRatio]?.[imageSize];
    body.aspectRatio = pixels || '864x1152';
    delete (body as Record<string, unknown>).imageSize;
  }

  return body;
}

/** POST 提交生成任务，返回 job id */
export async function submitGenerate(
  baseUrl: string,
  apiKey: string,
  body: GenerateRequest,
  signal?: AbortSignal,
): Promise<{ id: string; status: string; error?: string }> {
  const resp = await fetch(`${baseUrl}/v1/api/generate`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${apiKey}`,
    },
    body: JSON.stringify(body),
    signal,
  });

  if (!resp.ok) {
    const text = await resp.text().catch(() => '');
    return { id: '', status: resp.status >= 500 ? 'running' : 'failed', error: text || `HTTP ${resp.status}` };
  }

  const data = (await resp.json()) as GenerateResponse;
  if (!isValidResponse(data)) {
    return { id: '', status: 'failed', error: '响应格式异常' };
  }

  if (data.status === 'failed' || data.status === 'violation') {
    return { id: data.id || '', status: data.status, error: data.error || data.status };
  }

  if (!data.id) {
    return { id: '', status: 'failed', error: '响应缺少任务 ID' };
  }

  return { id: data.id, status: data.status };
}

/** GET 查询任务结果 */
export async function queryResult(
  baseUrl: string,
  apiKey: string,
  jobId: string,
  signal?: AbortSignal,
): Promise<GenerateResponse> {
  const resp = await fetch(`${baseUrl}/v1/api/result?id=${encodeURIComponent(jobId)}`, {
    headers: { Authorization: `Bearer ${apiKey}` },
    signal,
  });

  if (!resp.ok) {
    return { id: jobId, status: 'running', error: `HTTP ${resp.status}` };
  }

  const data = (await resp.json()) as GenerateResponse;
  if (!isValidResponse(data)) {
    return { id: jobId, status: 'failed', error: '响应格式异常' };
  }
  return data;
}

/** 运行时校验响应结构 */
function isValidResponse(data: unknown): data is GenerateResponse {
  if (!data || typeof data !== 'object') return false;
  const d = data as Record<string, unknown>;
  if (typeof d.id !== 'string') return false;
  const validStatus = ['running', 'succeeded', 'failed', 'violation'];
  if (!validStatus.includes(d.status as string)) return false;
  if (d.results !== undefined) {
    if (!Array.isArray(d.results)) return false;
    for (const r of d.results) {
      if (!r || typeof r !== 'object' || typeof (r as Record<string, unknown>).url !== 'string') return false;
    }
  }
  return true;
}

/** 判断是否为可重试的瞬时错误 */
export function isTransientError(error: string): boolean {
  if (!error) return false;
  // HTTP 5xx / 429 → 瞬时
  if (/^HTTP 5\d{2}$/.test(error)) return true;
  if (/^HTTP 429$/.test(error)) return true;
  // fetch failed / abort → 瞬时
  if (error.includes('fetch failed') || error.includes('abort') || error === 'AbortError') return true;
  if (error === 'The operation was aborted') return true;
  return false;
}

/** 带超时的 fetch wrapper */
export async function fetchWithTimeout(url: string, options: RequestInit, timeoutMs: number = TIMEOUT_MS): Promise<Response> {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), timeoutMs);
  try {
    const resp = await fetch(url, { ...options, signal: controller.signal });
    return resp;
  } finally {
    clearTimeout(timer);
  }
}

/** gpt-image-2-vip 像素换算 */
export function vipPixelSize(aspectRatio: string, imageSize: string): string {
  return VIP_PIXEL_MAP[aspectRatio]?.[imageSize] || '864x1152';
}

