import * as vscode from 'vscode';
import * as path from 'path';
import * as fs from 'fs';
import { submitGenerate, queryResult, buildRequestBody, isTransientError, fetchWithTimeout } from './api';
import { extToMime, extFromUrl, isImageExt, type JobState, type TaskInfo, type HistoryEntry } from './shared';
import type { ConfigManager } from './config';
import { getPrompt } from './prompt';

const POLL_INTERVAL = 4_000;
const TASK_TIMEOUT_MS = 10 * 60 * 1_000;
const MAX_POLL_RETRIES = 3;

export class TaskManager {
  private tasks: TaskInfo[] = [];
  private configManager: ConfigManager;
  private pollTimer: ReturnType<typeof setInterval> | null = null;
  private polling = false;
  private onUpdate: () => void;

  constructor(configManager: ConfigManager, onUpdate: () => void) {
    this.configManager = configManager;
    this.onUpdate = onUpdate;
  }

  getTasks(): TaskInfo[] {
    return this.tasks;
  }

  /** 提交新任务 */
  async submit(
    mdPath: string,
    model: string,
    aspectRatio: string,
    imageSize: string,
    concurrency: number,
  ): Promise<string | null> {
    const config = await this.configManager.getConfig();
    if (!config.apiKey) {
      vscode.window.showErrorMessage('请先在设置中配置 API Key');
      return null;
    }

    const mdDir = path.dirname(mdPath);
    const mdFileName = path.basename(mdPath, '.md');
    const mdContent = fs.readFileSync(mdPath, 'utf-8');

    if (!mdContent.trim()) {
      vscode.window.showErrorMessage('内容为空');
      return null;
    }

    // 解析参考图
    const { parseMarkdown } = require('./parser');
    let parseResult;
    try {
      parseResult = parseMarkdown(mdContent, mdDir);
    } catch (e: any) {
      // 参考图读取失败
      if (e.message?.startsWith('REF_FAIL:')) {
        const paths = e.message.replace('REF_FAIL:', '').split('\n').filter(Boolean);
        vscode.window.showErrorMessage(`参考图读取失败：\n${paths.join('\n')}`);
        return null;
      }
      throw e;
    }

    // 组装最终 prompt
    const prompt = getPrompt(mdPath, model, parseResult.body, this.configManager);

    // 创建任务文件夹
    const now = new Date();
    const ts = `${String(now.getFullYear()).slice(2)}${pad2(now.getMonth() + 1)}${pad2(now.getDate())}${pad2(now.getHours())}${pad2(now.getMinutes())}${pad2(now.getSeconds())}`;
    let seq = 1;
    let folderName = `task-${ts}-${seq}`;
    while (fs.existsSync(path.join(mdDir, folderName))) {
      seq++;
      folderName = `task-${ts}-${seq}`;
    }
    const folderPath = path.join(mdDir, folderName);
    fs.mkdirSync(folderPath, { recursive: true });

    const taskId = folderName;

    // 创建 N 个 job
    const jobs: JobState[] = [];
    for (let i = 0; i < concurrency; i++) {
      jobs.push({ index: i + 1, id: null, status: 'submitting', progress: 0, error: null, images: [] });
    }

    const task: TaskInfo = {
      id: taskId,
      folderName,
      folderPath,
      mdFileName,
      model,
      jobs,
      startedAt: Date.now(),
      sessionStart: Date.now(),
    };

    this.tasks.unshift(task);
    this.persist();
    this.onUpdate();

    // 后台发送 N 个请求
    const apiKey = config.apiKey;
    const baseUrl = config.baseUrl;
    const refUris = parseResult.refImages.map((r: { dataUri: string }) => r.dataUri);

    this.submitJobs(task, baseUrl, apiKey, prompt, refUris, model, aspectRatio, imageSize, concurrency);

    return taskId;
  }

  private async submitJobs(
    task: TaskInfo,
    baseUrl: string,
    apiKey: string,
    prompt: string,
    images: string[],
    model: string,
    aspectRatio: string,
    imageSize: string,
    concurrency: number,
  ) {
    let allFailed = true;
    const errors: string[] = [];

    const promises = task.jobs.map(async (job) => {
      try {
        const body = buildRequestBody(model, prompt, images, aspectRatio, imageSize);
        const result = await submitGenerate(baseUrl, apiKey, body);
        if (result.id) {
          job.id = result.id;
          job.status = 'running';
          allFailed = false;
        } else {
          job.status = result.status === 'violation' ? 'violation' : 'failed';
          job.error = result.error || '提交失败';
          errors.push(job.error);
        }
      } catch (e: any) {
        job.status = 'failed';
        job.error = e.message || '提交异常';
        errors.push(job.error);
      }
      this.persist();
      this.onUpdate();
    });

    await Promise.all(promises);

    if (allFailed) {
      // 全部失败：移除任务，删除空文件夹
      this.tasks = this.tasks.filter((t) => t.id !== task.id);
      try { fs.rmdirSync(task.folderPath); } catch { /* empty */ }
      this.persist();
      this.onUpdate();
      const uniqueErrors = [...new Set(errors.filter(Boolean))];
      vscode.window.showErrorMessage(`全部提交失败：${uniqueErrors.join('; ')}`);
      return;
    }

    this.ensurePolling();
    this.onUpdate();
  }

  /** 恢复未完成任务 */
  async resume() {
    const stored = this.configManager.get<TaskInfo[]>('pendingTasks', []);
    if (stored.length === 0) return;

    for (const task of stored) {
      // submitting 态无 id 的直接判失败
      for (const job of task.jobs) {
        if (job.status === 'submitting' && !job.id) {
          job.status = 'failed';
          job.error = '提交未完成';
        }
      }
      // 重置超时计时
      task.sessionStart = Date.now();
    }

    this.tasks = stored;
    // 检查是否有仍在 running 的 job
    const hasRunning = this.tasks.some((t) => t.jobs.some((j) => j.status === 'running'));
    if (hasRunning) {
      await this.pollAll();
      this.ensurePolling();
    }
    this.onUpdate();
  }

  /** 确保轮询定时器运转 */
  private ensurePolling() {
    if (this.pollTimer) return;
    this.pollTimer = setInterval(() => this.pollAll(), POLL_INTERVAL);
  }

  /** 停止轮询 */
  private stopPolling() {
    if (this.pollTimer) {
      clearInterval(this.pollTimer);
      this.pollTimer = null;
    }
  }

  /** 重入锁保护的轮询 */
  private async pollAll() {
    if (this.polling) return;
    this.polling = true;
    try {
      const config = await this.configManager.getConfig();
      const apiKey = config.apiKey;
      const baseUrl = config.baseUrl;
      let hasRunning = false;

      for (const task of this.tasks) {
        // 超时兜底
        if (Date.now() - task.sessionStart > TASK_TIMEOUT_MS) {
          for (const job of task.jobs) {
            if (job.status === 'running' || job.status === 'submitting') {
              job.status = 'failed';
              job.error = '任务超时';
            }
          }
          continue;
        }

        for (const job of task.jobs) {
          if (job.status !== 'running') continue;
          hasRunning = true;

          try {
            const result = await queryResult(baseUrl, apiKey, job.id!);
            if (result.status === 'succeeded') {
              job.status = 'succeeded';
              job.progress = 100;
              // 下载结果
              if (result.results) {
                let imgIndex = this.getNextImageIndex(task);
                for (const r of result.results) {
                  try {
                    const ext = extFromUrl(r.url);
                    const validExt = isImageExt(ext) ? ext : 'png';
                    const fileName = `${task.mdFileName}-${imgIndex}.${validExt}`;
                    const filePath = path.join(task.folderPath, fileName);
                    await this.downloadFile(r.url, filePath);
                    job.images.push(fileName);
                    imgIndex++;
                  } catch (e: any) {
                    job.error = (job.error ? job.error + '; ' : '') + `下载失败: ${e.message}`;
                  }
                }
              }
            } else if (result.status === 'failed' || result.status === 'violation') {
              job.status = result.status;
              job.error = result.error || result.status;
            } else if (result.status === 'running') {
              job.progress = result.progress || 0;
            }
          } catch (e: any) {
            const errMsg = e.message || '轮询异常';
            if (isTransientError(errMsg)) {
              // 瞬时错误，保持 running 下轮重试
              hasRunning = true;
            } else {
              job.status = 'failed';
              job.error = errMsg;
            }
          }
        }
      }

      this.persist();
      this.onUpdate();

      // 终结任务处理
      const finished = this.tasks.filter((t) => t.jobs.every((j) => j.status !== 'running' && j.status !== 'submitting'));
      for (const task of finished) {
        await this.finalizeTask(task);
      }

      if (!hasRunning && this.tasks.length === 0) {
        this.stopPolling();
      }
    } finally {
      this.polling = false;
    }
  }

  /** 任务终结处理 */
  private async finalizeTask(task: TaskInfo) {
    this.tasks = this.tasks.filter((t) => t.id !== task.id);

    const allImages = task.jobs.flatMap((j) => j.images);
    const failedJobs = task.jobs.filter((j) => j.status === 'failed' || j.status === 'violation');
    const errors = [...new Set(failedJobs.map((j) => j.error).filter(Boolean))];

    if (allImages.length === 0) {
      // 无成图：删空文件夹
      try { fs.rmdirSync(task.folderPath); } catch { /* empty */ }
      if (errors.length > 0) {
        vscode.window.showErrorMessage(`生成失败：${errors.join('; ')}`);
      }
    } else if (errors.length > 0) {
      vscode.window.showWarningMessage(`部分生成失败：${errors.join('; ')}`);
    }

    this.persist();
  }

  /** 下载文件 */
  private async downloadFile(url: string, destPath: string): Promise<void> {
    const resp = await fetchWithTimeout(url, {});
    if (!resp.ok) throw new Error(`下载失败 HTTP ${resp.status}`);
    const buffer = Buffer.from(await resp.arrayBuffer());
    fs.writeFileSync(destPath, buffer);
  }

  private getNextImageIndex(task: TaskInfo): number {
    let maxIdx = 0;
    for (const job of task.jobs) {
      for (const img of job.images) {
        // 从文件名提取序号（格式: mdName-N.ext）
        const match = img.match(/-(\d+)\.\w+$/);
        if (match) {
          const n = parseInt(match[1], 10);
          if (n > maxIdx) maxIdx = n;
        }
      }
    }
    return maxIdx + 1;
  }

  /** 持久化进行中任务 */
  private persist() {
    this.configManager.set('pendingTasks', this.tasks).catch(() => {});
  }

  /** 获取历史任务 */
  getHistory(mdPath: string): HistoryEntry[] {
    if (!mdPath) return [];
    const mdDir = path.dirname(mdPath);
    if (!fs.existsSync(mdDir)) return [];

    const taskFolders: HistoryEntry[] = [];
    const pendingFolders = new Set(this.tasks.map((t) => t.folderName));

    try {
      const entries = fs.readdirSync(mdDir, { withFileTypes: true });
      for (const entry of entries) {
        if (!entry.isDirectory() || !entry.name.startsWith('task-')) continue;
        if (pendingFolders.has(entry.name)) continue;

        const folderPath = path.join(mdDir, entry.name);
        const files = fs.readdirSync(folderPath).filter((f) => {
          const ext = path.extname(f).toLowerCase().replace('.', '');
          return isImageExt(ext);
        });

        if (files.length === 0) continue;

        taskFolders.push({
          folderName: entry.name,
          folderPath,
          imageCount: files.length,
          images: files.sort(),
        });
      }
    } catch { /* ignore */ }

    taskFolders.sort((a, b) => b.folderName.localeCompare(a.folderName));
    return taskFolders;
  }

  dispose() {
    this.stopPolling();
  }
}

function pad2(n: number): string {
  return String(n).padStart(2, '0');
}

import * as vscode from 'vscode';
import * as path from 'path';
import * as fs from 'fs';
import { buildRequestBody } from './api';
import { parseMarkdown } from './parser';
import { getPrompt } from './prompt';
import type { ConfigManager } from './config';
import type { ExtensionConfig } from './shared';

/**
 * 预览请求：走与真实提交完全一致的解析与请求体构造，但不调 API，
 * 结果输出到临时预览文档。
 */
export async function showPreview(
  mdPath: string,
  configManager: ConfigManager,
) {
  const config = await configManager.getConfig();
  const mdDir = path.dirname(mdPath);
  const mdContent = fs.readFileSync(mdPath, 'utf-8');

  if (!mdContent.trim()) {
    vscode.window.showErrorMessage('内容为空');
    return;
  }

  let parseResult;
  try {
    parseResult = parseMarkdown(mdContent, mdDir);
  } catch (e: any) {
    if (e.message?.startsWith('REF_FAIL:')) {
      const paths = e.message.replace('REF_FAIL:', '').split('\n').filter(Boolean);
      vscode.window.showErrorMessage(`参考图读取失败：\n${paths.join('\n')}`);
      return;
    }
    throw e;
  }

  const prompt = getPrompt(mdPath, config.model, parseResult.body, configManager);
  const refUris = parseResult.refImages.map((r: { dataUri: string }) => r.dataUri);

  const body = buildRequestBody(config.model, prompt, refUris, config.aspectRatio, config.imageSize);

  // 构造预览内容
  const lines: string[] = [];

  // 1. 最终提示词
  lines.push('## 最终提示词');
  lines.push('');
  lines.push(prompt || '(空)');
  lines.push('');

  // 2. 请求地址
  lines.push('## 请求地址');
  lines.push('');
  lines.push(`POST ${config.baseUrl}/v1/api/generate`);
  lines.push('');

  // 3. 请求参数 JSON（剔除 prompt 与 images）
  const paramsForDisplay: Record<string, unknown> = {};
  for (const [k, v] of Object.entries(body)) {
    if (k !== 'prompt' && k !== 'images') {
      paramsForDisplay[k] = v;
    }
  }
  lines.push('## 请求参数（已剔除 prompt 与 images）');
  lines.push('');
  lines.push('```json');
  lines.push(JSON.stringify(paramsForDisplay, null, 2));
  lines.push('```');
  lines.push('');

  // 4. 参考图概览
  lines.push('## 参考图概览');
  lines.push('');
  if (parseResult.refImages.length === 0) {
    lines.push('无参考图');
  } else {
    for (const ref of parseResult.refImages) {
      const preview = ref.dataUri.slice(0, 48);
      const totalLen = ref.dataUri.length;
      lines.push(`- image${ref.index}: ${preview}…（${totalLen} 字符）`);
    }
  }

  // 打开预览文档
  const doc = await vscode.workspace.openTextDocument({
    content: lines.join('\n'),
    language: 'markdown',
  });
  await vscode.window.showTextDocument(doc, { preview: true });
}

import * as vscode from 'vscode';
import * as path from 'path';
import * as fs from 'fs';
import { isImageExt, type MaterialLibrary, type MaterialImage } from './shared';

const MAX_DEPTH = 3;
const MAX_FILES = 500;

/** 扫描目录内图片（递归，深度/数量上限保护） */
export function scanImages(
  dirPath: string,
  recursive: boolean,
  webviewUriFn: (p: string) => vscode.Uri,
): MaterialImage[] {
  const images: MaterialImage[] = [];
  if (!fs.existsSync(dirPath)) return images;

  function walk(currentDir: string, depth: number) {
    if (images.length >= MAX_FILES) return;
    if (recursive && depth > MAX_DEPTH) return;

    let entries: fs.Dirent[];
    try {
      entries = fs.readdirSync(currentDir, { withFileTypes: true });
    } catch {
      return;
    }

    for (const entry of entries) {
      if (images.length >= MAX_FILES) return;
      if (entry.isFile()) {
        const ext = path.extname(entry.name).toLowerCase().replace('.', '');
        if (isImageExt(ext)) {
          const fullPath = path.join(currentDir, entry.name);
          images.push({
            path: fullPath,
            name: entry.name,
            webviewUri: webviewUriFn(fullPath).toString(),
          });
        }
      } else if (recursive && entry.isDirectory()) {
        walk(path.join(currentDir, entry.name), depth + 1);
      }
    }
  }

  walk(dirPath, 1);
  return images;
}

/** 生成自动素材库（按 MD 路径逐层向上） */
export function buildAutoLibraries(
  mdPath: string,
  workspaceRoot: string,
  webviewUriFn: (p: string) => vscode.Uri,
): MaterialLibrary[] {
  if (!mdPath || !workspaceRoot) return [];

  const libs: MaterialLibrary[] = [];
  const mdDir = path.dirname(mdPath);
  const rel = path.relative(workspaceRoot, mdDir);
  if (!rel || rel.startsWith('..')) return [];

  // 从工作区根的下一层开始，到 MD 所在目录
  const parts = rel.split(path.sep);
  let current = workspaceRoot;

  for (let i = 0; i < parts.length; i++) {
    current = path.join(current, parts[i]);
    // 跳过工作区根那层
    if (i < 0) continue;
    // 当前层文件夹名就是库名
    const libName = parts[i] || current;
    const files = fs.readdirSync(current).filter((f) => {
      const fullPath = path.join(current, f);
      try {
        return fs.statSync(fullPath).isFile() && isImageExt(path.extname(f).toLowerCase().replace('.', ''));
      } catch {
        return false;
      }
    });

    if (files.length === 0) continue;

    const images: MaterialImage[] = files.map((f) => {
      const fullPath = path.join(current, f);
      return {
        path: fullPath,
        name: f,
        webviewUri: webviewUriFn(fullPath).toString(),
      };
    });

    libs.push({ name: libName, path: current, images });
  }

  return libs;
}

/** 生成相对 MD 的 POSIX 风格相对路径引用 */
export function relativeImagePath(mdPath: string, imagePath: string): { path: string; needsBracket: boolean } | null {
  const mdDir = path.dirname(mdPath);

  // 跨盘符检测
  try {
    const rel = path.relative(mdDir, imagePath);
    if (rel.startsWith('..') && rel.includes(':')) {
      return null; // 跨盘符
    }
  } catch {
    return null;
  }

  let rel = path.relative(mdDir, imagePath).split(path.sep).join('/');
  const needsBracket = /\s|\(|\)/.test(rel);

  if (!rel.startsWith('..')) {
    rel = './' + rel;
  }

  return { path: rel, needsBracket };
}

/** 生成 Markdown 图片引用 */
export function buildImageRef(mdPath: string, imagePath: string): string | null {
  const rel = relativeImagePath(mdPath, imagePath);
  if (!rel) return null;

  const alt = path.basename(imagePath, path.extname(imagePath));

  if (rel.needsBracket) {
    return `![${alt}](<${rel.path}>)`;
  }
  return `![${alt}](${rel.path})`;
}

import * as vscode from 'vscode';
import * as path from 'path';
import * as fs from 'fs';
import type { ConfigManager } from './config';

/** 组装最终 prompt = 模型注入句 + IMAGES.md + 替换后正文 */
export function getPrompt(
  mdPath: string,
  model: string,
  parsedBody: string,
  configManager: ConfigManager,
): string {
  const parts: string[] = [];

  // 1. 模型注入句
  const injections = configManager.get<Record<string, string>>('modelInjections', {});
  const injection = injections[model];
  if (injection) {
    parts.push(injection);
  }

  // 2. 工作区根 IMAGES.md
  const workspaceFolder = vscode.workspace.getWorkspaceFolder(vscode.Uri.file(mdPath));
  if (workspaceFolder) {
    const imagesMdPath = path.join(workspaceFolder.uri.fsPath, 'IMAGES.md');
    try {
      if (fs.existsSync(imagesMdPath)) {
        const content = fs.readFileSync(imagesMdPath, 'utf-8').trim();
        if (content) {
          parts.push(content);
        }
      }
    } catch { /* 静默跳过 */ }
  }

  // 3. 替换后正文
  const trimmed = parsedBody.trim();
  if (trimmed) {
    parts.push(trimmed);
  }

  return parts.join('\n\n');
}

