9	const POLL_INTERVAL = 4_000;
10	const TASK_TIMEOUT_MS = 10 * 60 * 1_000;
11	const MAX_POLL_RETRIES = 3;
12	
13	export class TaskManager {
14	  private tasks: TaskInfo[] = [];
15	  private configManager: ConfigManager;
16	  private pollTimer: ReturnType<typeof setInterval> | null = null;
17	  private polling = false;
18	  private onUpdate: () => void;
19	
20	  constructor(configManager: ConfigManager, onUpdate: () => void) {
21	    this.configManager = configManager;
22	    this.onUpdate = onUpdate;
23	  }
24	
25	  getTasks(): TaskInfo[] {
26	    return this.tasks;
27	  }
28	
29	  /** 提交新任务 */
30	  async submit(
31	    mdPath: string,
32	    model: string,
33	    aspectRatio: string,
34	    imageSize: string,
35	    concurrency: number,
36	  ): Promise<string | null> {
37	    const config = await this.configManager.getConfig();
38	    if (!config.apiKey) {
39	      vscode.window.showErrorMessage('请先在设置中配置 API Key');
40	      return null;
41	    }
42	
43	    const mdDir = path.dirname(mdPath);
44	    const mdFileName = path.basename(mdPath, '.md');
45	    const mdContent = fs.readFileSync(mdPath, 'utf-8');
46	
47	    if (!mdContent.trim()) {
48	      vscode.window.showErrorMessage('内容为空');
49	      return null;
50	    }
51	
52	    // 解析参考图
53	    const { parseMarkdown } = require('./parser');
54	    let parseResult;
55	    try {
56	      parseResult = parseMarkdown(mdContent, mdDir);
57	    } catch (e: any) {
58	      // 参考图读取失败
59	      if (e.message?.startsWith('REF_FAIL:')) {
60	        const paths = e.message.replace('REF_FAIL:', '').split('\n').filter(Boolean);
61	        vscode.window.showErrorMessage(`参考图读取失败：\n${paths.join('\n')}`);
62	        return null;
63	      }
64	      throw e;
65	    }
66	
67	    // 组装最终 prompt
68	    const prompt = getPrompt(mdPath, model, parseResult.body, this.configManager);
69	
70	    // 创建任务文件夹
71	    const now = new Date();
72	    const ts = `${String(now.getFullYear()).slice(2)}${pad2(now.getMonth() + 1)}${pad2(now.getDate())}${pad2(now.getHours())}${pad2(now.getMinutes())}${pad2(now.getSeconds())}`;
73	    let seq = 1;
74	    let folderName = `task-${ts}-${seq}`;
75	    while (fs.existsSync(path.join(mdDir, folderName))) {
76	      seq++;
77	      folderName = `task-${ts}-${seq}`;
78	    }
79	    const folderPath = path.join(mdDir, folderName);
80	    fs.mkdirSync(folderPath, { recursive: true });
81	
82	    const taskId = folderName;
83	
84	    // 创建 N 个 job
85	    const jobs: JobState[] = [];
86	    for (let i = 0; i < concurrency; i++) {
87	      jobs.push({ index: i + 1, id: null, status: 'submitting', progress: 0, error: null, images: [] });
88	    }
89	
90	    const task: TaskInfo = {
91	      id: taskId,
92	      folderName,
93	      folderPath,
94	      mdFileName,
95	      model,
96	      jobs,
97	      startedAt: Date.now(),
98	      sessionStart: Date.now(),
99	    };
100	
101	    this.tasks.unshift(task);
102	    this.persist();
103	    this.onUpdate();
104	
105	    // 后台发送 N 个请求
106	    const apiKey = config.apiKey;
107	    const baseUrl = config.baseUrl;
108	    const refUris = parseResult.refImages.map((r: { dataUri: string }) => r.dataUri);
109	
110	    this.submitJobs(task, baseUrl, apiKey, prompt, refUris, model, aspectRatio, imageSize, concurrency);
