113	  }
114	
115	  private async submitJobs(
116	    task: TaskInfo,
117	    baseUrl: string,
118	    apiKey: string,
119	    prompt: string,
120	    images: string[],
121	    model: string,
122	    aspectRatio: string,
123	    imageSize: string,
124	    concurrency: number,
125	  ) {
126	    let allFailed = true;
127	    const errors: string[] = [];
128	
129	    const promises = task.jobs.map(async (job) => {
130	      try {
131	        const body = buildRequestBody(model, prompt, images, aspectRatio, imageSize);
132	        const result = await submitGenerate(baseUrl, apiKey, body);
133	        if (result.id) {
134	          job.id = result.id;
135	          job.status = 'running';
136	          allFailed = false;
137	        } else {
138	          job.status = result.status === 'violation' ? 'violation' : 'failed';
139	          job.error = result.error || '提交失败';
140	          errors.push(job.error);
141	        }
142	      } catch (e: any) {
143	        job.status = 'failed';
144	        job.error = e.message || '提交异常';
145	        errors.push(job.error);
146	      }
147	      this.persist();
148	      this.onUpdate();
149	    });
150	
151	    await Promise.all(promises);
152	
153	    if (allFailed) {
154	      // 全部失败：移除任务，删除空文件夹
155	      this.tasks = this.tasks.filter((t) => t.id !== task.id);
156	      try { fs.rmdirSync(task.folderPath); } catch { /* empty */ }
157	      this.persist();
158	      this.onUpdate();
159	      const uniqueErrors = [...new Set(errors.filter(Boolean))];
160	      vscode.window.showErrorMessage(`全部提交失败：${uniqueErrors.join('; ')}`);
161	      return;
162	    }
163	
164	    this.ensurePolling();
165	    this.onUpdate();
166	  }
167	
168	  /** 恢复未完成任务 */
169	  async resume() {
170	    const stored = this.configManager.get<TaskInfo[]>('pendingTasks', []);
171	    if (stored.length === 0) return;
172	
173	    for (const task of stored) {
174	      // submitting 态无 id 的直接判失败
175	      for (const job of task.jobs) {
176	        if (job.status === 'submitting' && !job.id) {
177	          job.status = 'failed';
178	          job.error = '提交未完成';
179	        }
180	      }
181	      // 重置超时计时
182	      task.sessionStart = Date.now();
183	    }
184	
185	    this.tasks = stored;
186	    // 检查是否有仍在 running 的 job
187	    const hasRunning = this.tasks.some((t) => t.jobs.some((j) => j.status === 'running'));
188	    if (hasRunning) {
189	      await this.pollAll();
190	      this.ensurePolling();
191	    }
192	    this.onUpdate();
193	  }
194	
195	  /** 确保轮询定时器运转 */
196	  private ensurePolling() {
197	    if (this.pollTimer) return;
198	    this.pollTimer = setInterval(() => this.pollAll(), POLL_INTERVAL);
199	  }
200	
201	  /** 停止轮询 */
202	  private stopPolling() {
203	    if (this.pollTimer) {
204	      clearInterval(this.pollTimer);
205	      this.pollTimer = null;
206	    }
207	  }
208	
209	  /** 重入锁保护的轮询 */
210	  private async pollAll() {
211	    if (this.polling) return;
212	    this.polling = true;
213	    try {
214	      const config = await this.configManager.getConfig();
215	      const apiKey = config.apiKey;
216	      const baseUrl = config.baseUrl;
217	      let hasRunning = false;
218	
219	      for (const task of this.tasks) {
220	        // 超时兜底
221	        if (Date.now() - task.sessionStart > TASK_TIMEOUT_MS) {
222	          for (const job of task.jobs) {
223	            if (job.status === 'running' || job.status === 'submitting') {
224	              job.status = 'failed';
225	              job.error = '任务超时';
226	            }
227	          }
228	          continue;
229	        }
230	
231	        for (const job of task.jobs) {
232	          if (job.status !== 'running') continue;
233	          hasRunning = true;
234	
235	          try {
236	            const result = await queryResult(baseUrl, apiKey, job.id!);
237	            if (result.status === 'succeeded') {
238	              job.status = 'succeeded';
239	              job.progress = 100;
240	              // 下载结果
241	              if (result.results) {
242	                let imgIndex = this.getNextImageIndex(task);
243	                for (const r of result.results) {
244	                  try {
245	                    const ext = extFromUrl(r.url);
246	                    const validExt = isImageExt(ext) ? ext : 'png';
247	                    const fileName = `${task.mdFileName}-${imgIndex}.${validExt}`;
248	                    const filePath = path.join(task.folderPath, fileName);
249	                    await this.downloadFile(r.url, filePath);
250	                    job.images.push(fileName);
251	                    imgIndex++;
252	                  } catch (e: any) {
253	                    job.error = (job.error ? job.error + '; ' : '') + `下载失败: ${e.message}`;
254	                  }
255	                }
256	              }
257	            } else if (result.status === 'failed' || result.status === 'violation') {
258	              job.status = result.status;
259	              job.error = result.error || result.status;
260	            } else if (result.status === 'running') {
261	              job.progress = result.progress || 0;
262	            }
263	          } catch (e: any) {
264	            const errMsg = e.message || '轮询异常';
265	            if (isTransientError(errMsg)) {
266	              // 瞬时错误，保持 running 下轮重试
267	              hasRunning = true;
268	            } else {
269	              job.status = 'failed';
270	              job.error = errMsg;
271	            }
272	          }
273	        }
274	      }
275	
276	      this.persist();
277	      this.onUpdate();
278	
279	      // 终结任务处理
280	      const finished = this.tasks.filter((t) => t.jobs.every((j) => j.status !== 'running' && j.status !== 'submitting'));
281	      for (const task of finished) {
282	        await this.finalizeTask(task);
283	      }
284	
285	      if (!hasRunning && this.tasks.length === 0) {
286	        this.stopPolling();
287	      }
288	    } finally {
289	      this.polling = false;
290	    }
291	  }
292	
293	  /** 任务终结处理 */
294	  private async finalizeTask(task: TaskInfo) {
295	    this.tasks = this.tasks.filter((t) => t.id !== task.id);
296	
297	    const allImages = task.jobs.flatMap((j) => j.images);
298	    const failedJobs = task.jobs.filter((j) => j.status === 'failed' || j.status === 'violation');
299	    const errors = [...new Set(failedJobs.map((j) => j.error).filter(Boolean))];
300	
301	    if (allImages.length === 0) {
302	      // 无成图：删空文件夹
303	      try { fs.rmdirSync(task.folderPath); } catch { /* empty */ }
304	      if (errors.length > 0) {
305	        vscode.window.showErrorMessage(`生成失败：${errors.join('; ')}`);
306	      }
307	    } else if (errors.length > 0) {
308	      vscode.window.showWarningMessage(`部分生成失败：${errors.join('; ')}`);
309	    }
310	
311	    this.persist();
312	  }
313	
314	  /** 下载文件 */
315	  private async downloadFile(url: string, destPath: string): Promise<void> {
316	    const resp = await fetchWithTimeout(url, {});
317	    if (!resp.ok) throw new Error(`下载失败 HTTP ${resp.status}`);
318	    const buffer = Buffer.from(await resp.arrayBuffer());
319	    fs.writeFileSync(destPath, buffer);
320	  }
321	
322	  private getNextImageIndex(task: TaskInfo): number {
323	    let maxIdx = 0;
324	    for (const job of task.jobs) {
325	      for (const img of job.images) {
326	        // 从文件名提取序号（格式: mdName-N.ext）
327	        const match = img.match(/-(\d+)\.\w+$/);
328	        if (match) {
329	          const n = parseInt(match[1], 10);
330	          if (n > maxIdx) maxIdx = n;
331	        }
332	      }
333	    }
334	    return maxIdx + 1;
335	  }
336	
337	  /** 持久化进行中任务 */
338	  private persist() {
339	    this.configManager.set('pendingTasks', this.tasks).catch(() => {});
340	  }
341	
342	  /** 获取历史任务 */
343	  getHistory(mdPath: string): HistoryEntry[] {
344	    if (!mdPath) return [];
345	    const mdDir = path.dirname(mdPath);
346	    if (!fs.existsSync(mdDir)) return [];
347	
348	    const taskFolders: HistoryEntry[] = [];
349	    const pendingFolders = new Set(this.tasks.map((t) => t.folderName));
350	
351	    try {
352	      const entries = fs.readdirSync(mdDir, { withFileTypes: true });
353	      for (const entry of entries) {
354	        if (!entry.isDirectory() || !entry.name.startsWith('task-')) continue;
355	        if (pendingFolders.has(entry.name)) continue;
356	
357	        const folderPath = path.join(mdDir, entry.name);
358	        const files = fs.readdirSync(folderPath).filter((f) => {
359	          const ext = path.extname(f).toLowerCase().replace('.', '');
360	          return isImageExt(ext);
361	        });
362	
363	        if (files.length === 0) continue;
364	
365	        taskFolders.push({
366	          folderName: entry.name,
367	          folderPath,
368	          imageCount: files.length,
369	          images: files.sort(),
370	        });
371	      }
372	    } catch { /* ignore */ }
373	
374	    taskFolders.sort((a, b) => b.folderName.localeCompare(a.folderName));
375	    return taskFolders;
376	  }
377	
378	  dispose() {
379	    this.stopPolling();
380	  }
381	}
382	
383	function pad2(n: number): string {
384	  return String(n).padStart(2, '0');
385	}
