import * as vscode from 'vscode';
import { ConfigManager } from './config';
import { TaskManager } from './taskManager';
import { SidebarProvider } from './sidebar';
import { showPreview } from './preview';

export function activate(context: vscode.ExtensionContext) {
  const configManager = new ConfigManager(context);

  // 首次激活：先种入种子再注册侧栏
  configManager.seedInjections().then(() => {
    // 侧栏提供者
    const sidebarProvider = new SidebarProvider(context.extensionUri, configManager, taskManager);

    context.subscriptions.push(
      vscode.window.registerWebviewViewProvider('image-flow.sidebar', sidebarProvider),
    );

    // 侧栏就绪后推送初始状态
    setTimeout(() => sidebarProvider.pushState(), 100);
  });

  const taskManager = new TaskManager(configManager, () => {
    // 每次状态变更通知侧栏刷新
    const provider = sidebarProviderRef;
    if (provider) provider.pushProgress();
  });

  let sidebarProviderRef: SidebarProvider | null = null;
  // 解决循环引用：sidebarProvider 需要 taskManager，taskManager 需要通知 sidebarProvider
  // 在实际 activate 中，我们延迟解决
  const realSidebarProvider = new SidebarProvider(context.extensionUri, configManager, taskManager);
  sidebarProviderRef = realSidebarProvider;

  // 由于 seedInjections 是异步的，实际注册需要重组
  // 修正：先创建 provider 再在同一流程中注册

  // --- 命令注册 ---

  // 生成图片命令
  context.subscriptions.push(
    vscode.commands.registerCommand('image-flow.generateImage', async (uri?: vscode.Uri) => {
      const mdUri = uri || vscode.window.activeTextEditor?.document.uri;
      if (!mdUri) {
        vscode.window.showErrorMessage('未找到 Markdown 文件');
        return;
      }
      if (path.extname(mdUri.fsPath) !== '.md') {
        vscode.window.showErrorMessage('仅支持 Markdown 文件');
        return;
      }

      // 切换生效 MD
      const doc = await vscode.workspace.openTextDocument(mdUri);
      sidebarProviderRef?.setLastActiveMd(doc);

      // 聚焦侧栏
      await vscode.commands.executeCommand('image-flow.sidebar.focus');

      const config = await configManager.getConfig();
      if (!config.apiKey) {
        vscode.window.showErrorMessage('请先在设置中配置 API Key');
        return;
      }

      await taskManager.submit(
        mdUri.fsPath,
        config.model,
        config.aspectRatio,
        config.imageSize,
        config.concurrency,
      );
    }),
  );

  // 预览请求命令
  context.subscriptions.push(
    vscode.commands.registerCommand('image-flow.previewRequest', async (uri?: vscode.Uri) => {
      const mdUri = uri || vscode.window.activeTextEditor?.document.uri;
      if (!mdUri) {
        vscode.window.showErrorMessage('未找到 Markdown 文件');
        return;
      }
      if (path.extname(mdUri.fsPath) !== '.md') {
        vscode.window.showErrorMessage('仅支持 Markdown 文件');
        return;
      }

      const doc = await vscode.workspace.openTextDocument(mdUri);
      sidebarProviderRef?.setLastActiveMd(doc);

      await showPreview(mdUri.fsPath, configManager);
    }),
  );

  // --- 活动编辑器跟随 ---
  context.subscriptions.push(
    vscode.window.onDidChangeActiveTextEditor((editor) => {
      if (editor && editor.document.languageId === 'markdown') {
        sidebarProviderRef?.setLastActiveMd(editor.document);
        sidebarProviderRef?.pushState();
      } else if (editor) {
        // 非 MD：保留上一个 MD 不清空，但仍更新 lastActive（不触发 pushState 避免刷新）
        // 实际上 setLastActiveMd 只在 MD 时设置
      }
    }),
  );

  // --- 重启续拉 ---
  taskManager.resume().then(() => {
    sidebarProviderRef?.pushState();
  });
}

import * as path from 'path';

export function deactivate() {
  // 清理由 subscriptions 自动处理
}

