import * as path from 'path';
import * as fs from 'fs';

export interface RefImage {
  /** 编号（从 1 开始） */
  index: number;
  /** data URI */
  dataUri: string;
  /** 原始路径 */
  originalPath: string;
}

export interface ParseResult {
  /** 替换后的正文（图片语法替换为 [imageN]） */
  body: string;
  /** 去重编号的参考图列表 */
  refImages: RefImage[];
}

/**
 * 解析 Markdown 正文，提取参考图并替换为 [imageN]
 * 匹配 `![alt](路径)` 与 `![alt](<路径>)`
 * 按首次出现顺序去重编号，同一路径复用同一序号
 * 任何参考图读取失败抛出 REF_FAIL: 错误
 */
export function parseMarkdown(mdContent: string, mdDir: string): ParseResult {
  const imageRefs = new Map<string, number>(); // 路径 → 编号
  const refImages: RefImage[] = [];
  const failedPaths: string[] = [];
  let nextIndex = 1;

  const imgRegex = /!\[([^\]]*)\]\((?:<([^>]+)>|([^)\s]+))\)/g;
  let match: RegExpExecArray | null;

  // 第一遍：收集所有引用
  const replacements: { start: number; end: number; rawPath: string }[] = [];

  while ((match = imgRegex.exec(mdContent)) !== null) {
    const rawPath = (match[2] || match[3] || '').trim();
    if (!rawPath) continue;
    replacements.push({ start: match.index, end: match.index + match[0].length, rawPath });
  }

  // 预检查所有参考图是否可读
  for (const { rawPath } of replacements) {
    if (imageRefs.has(rawPath)) continue;
    const absPath = path.resolve(mdDir, rawPath);
    try {
      fs.accessSync(absPath, fs.constants.R_OK);
    } catch {
      failedPaths.push(absPath);
    }
  }

  if (failedPaths.length > 0) {
    throw new Error(`REF_FAIL:${failedPaths.join('\n')}`);
  }

  // 第二遍：构建替换结果
  let body = mdContent;
  let offset = 0;

  for (const { start, end, rawPath } of replacements) {
    let idx: number;
    if (imageRefs.has(rawPath)) {
      idx = imageRefs.get(rawPath)!;
    } else {
      idx = nextIndex++;
      imageRefs.set(rawPath, idx);

      const absPath = path.resolve(mdDir, rawPath);
      const ext = path.extname(absPath).toLowerCase().replace('.', '');
      const mime = mimeFromExt(ext);
      const buffer = fs.readFileSync(absPath);
      const b64 = buffer.toString('base64');
      const dataUri = `data:${mime};base64,${b64}`;

      refImages.push({ index: idx, dataUri, originalPath: rawPath });
    }

    const replacement = `[image${idx}](${path.basename(rawPath, path.extname(rawPath))})`;
    body = body.slice(0, start + offset) + replacement + body.slice(end + offset);
    offset += replacement.length - (end - start);
  }

  return { body, refImages };
}

/** 根据扩展名推断 MIME */
export function mimeFromExt(ext: string): string {
  const m: Record<string, string> = {
    png: 'image/png',
    jpg: 'image/jpeg',
    jpeg: 'image/jpeg',
    gif: 'image/gif',
    webp: 'image/webp',
    bmp: 'image/bmp',
    svg: 'image/svg+xml',
  };
  return m[ext] || 'image/png';
}

/** 检查扩展名是否在图片白名单中 */
export function isImageExt(ext: string): boolean {
  const exts = ['png', 'jpg', 'jpeg', 'gif', 'webp', 'bmp', 'svg'];
  return exts.includes(ext.toLowerCase());
}

/** 从 URL 中提取文件扩展名 */
export function extFromUrl(url: string): string {
  try {
    const u = new URL(url);
    const basename = path.basename(u.pathname);
    const clean = basename.split('?')[0];
    const ext = path.extname(clean).toLowerCase().replace('.', '');
    return ext;
  } catch {
    return '';
  }
}

export { isImageExt as _isImageExt };

import * as vscode from 'vscode';
import * as path from 'path';
import type { ConfigManager } from './config';
import type { TaskManager } from './taskManager';
import type { ExtToWebview, WebviewToExt, MaterialLibrary } from './shared';
import { buildAutoLibraries, scanImages, buildImageRef } from './materialLib';

export class SidebarProvider implements vscode.WebviewViewProvider {
  private _view?: vscode.WebviewView;
  private configManager: ConfigManager;
  private taskManager: TaskManager;
  private extensionUri: vscode.Uri;
  private _lastActiveMd: vscode.TextDocument | null = null;

  constructor(
    extensionUri: vscode.Uri,
    configManager: ConfigManager,
    taskManager: TaskManager,
  ) {
    this.extensionUri = extensionUri;
    this.configManager = configManager;
    this.taskManager = taskManager;
  }

  resolveWebviewView(webviewView: vscode.WebviewView) {
    this._view = webviewView;

    this.refreshLocalResourceRoots();

    webviewView.webview.html = this.getHtml(webviewView.webview);

    webviewView.webview.onDidReceiveMessage(async (msg: WebviewToExt) => {
      await this.handleMessage(msg);
    });

    webviewView.onDidChangeVisibility(() => {
      if (webviewView.visible) {
        this.pushState();
      }
    });
  }

  /** 推送全量状态到 webview */
  async pushState() {
    if (!this._view) return;
    const config = await this.configManager.getConfig();

    this.post({
      type: 'config',
      config: { ...config, apiKey: config.apiKey ? '***' : '' },
    });

    const activeMd = this.getActiveMd();
    this.post({
      type: 'activeMd',
      filePath: activeMd?.uri.fsPath || null,
      fileName: activeMd ? path.basename(activeMd.uri.fsPath) : null,
    });

    const tasks = this.taskManager.getTasks();
    const history = activeMd ? this.taskManager.getHistory(activeMd.uri.fsPath) : [];
    this.post({ type: 'tasks', tasks, history });

    const materials = this.getMaterials(activeMd);
