      this._lastActiveMd = doc;
    }
  }

  private async handleMessage(msg: WebviewToExt) {
    switch (msg.type) {
      case 'generate':
        await this.handleGenerate();
        break;
      case 'preview':
        await vscode.commands.executeCommand('image-flow.previewRequest');
        break;
      case 'saveConfig':
        await this.configManager.set(msg.key, msg.value);
        // 回读确认并推送
        await this.pushState();
        break;
      case 'setApiKey':
        await this.configManager.setApiKey(msg.value);
        break;
      case 'addMaterialDir':
        await this.handleAddMaterialDir();
        break;
      case 'removeMaterialDir':
        await this.configManager.removeMaterialDir(msg.dir);
        await this.pushState();
        this.refreshLocalResourceRoots();
        break;
      case 'insertImage':
        await this.handleInsertImage(msg.imagePath);
        break;
      case 'openImage':
        await vscode.commands.executeCommand('vscode.open', vscode.Uri.file(msg.imagePath));
        break;
      case 'openUrl':
        await vscode.env.openExternal(vscode.Uri.parse(msg.url));
        break;
    }
  }

  private async handleGenerate() {
    const activeMd = this.getActiveMd();
    if (!activeMd) {
      vscode.window.showErrorMessage('未打开 Markdown 文件');
      return;
    }
    const config = await this.configManager.getConfig();

    const result = await this.taskManager.submit(
      activeMd.fsPath,
      config.model,
      config.aspectRatio,
      config.imageSize,
      config.concurrency,
    );

    if (result) {
      // 切换到任务标签
      this.post({ type: 'status', message: '任务已提交', isError: false });
      await this.pushState();
    }
  }

  private async handleAddMaterialDir() {
    const result = await vscode.window.showOpenDialog({
      canSelectFolders: true,
      canSelectFiles: false,
      canSelectMany: false,
    });
    if (result && result[0]) {
      await this.configManager.addMaterialDir(result[0].fsPath);
      await this.pushState();
      this.refreshLocalResourceRoots();
    }
  }

  private async handleInsertImage(imagePath: string) {
    const editor = vscode.window.activeTextEditor;
    const activeMd = this.getActiveMd();

    if (!editor || !activeMd || editor.document.uri.fsPath !== activeMd.uri.fsPath) {
      vscode.window.showWarningMessage('请先切换到生效的 Markdown 文件再插入引用');
      return;
    }

    const { buildImageRef } = require('./materialLib');
    const ref = buildImageRef(activeMd.fsPath, imagePath);
    if (!ref) {
      vscode.window.showWarningMessage('无法生成相对路径引用（可能跨盘符）');
      return;
    }

    await editor.edit((editBuilder) => {
      editBuilder.insert(editor.selection.active, ref);
    });
  }

  private getMaterials(activeMd: vscode.TextDocument | null) {
    const workspaces = vscode.workspace.workspaceFolders;
    const root = workspaces?.[0]?.uri.fsPath || '';

    const auto: MaterialLibrary[] = activeMd
      ? buildAutoLibraries(activeMd.fsPath, root, (p) => this.getWebviewUri(p))
      : [];

    const manualDirs = this.configManager.getMaterialDirs();
    const manual: MaterialLibrary[] = manualDirs.map((dir) => ({
      name: path.basename(dir),
      path: dir,
      images: scanImages(dir, true, (p) => this.getWebviewUri(p)),
    }));

    return { auto, manual };
  }

  private getWebviewUri(filePath: string): vscode.Uri {
    return this._view!.webview.asWebviewUri(vscode.Uri.file(filePath));
  }

  private refreshLocalResourceRoots() {
    if (!this._view) return;
    const roots: vscode.Uri[] = [];
    roots.push(vscode.Uri.joinPath(this.extensionUri, 'media'));

    const workspaces = vscode.workspace.workspaceFolders;
    if (workspaces) {
      for (const ws of workspaces) {
        roots.push(ws.uri);
      }
    }

    const manualDirs = this.configManager.getMaterialDirs();
    for (const dir of manualDirs) {
      roots.push(vscode.Uri.file(dir));
    }

    this._view.webview.options = {
      enableScripts: true,
      localResourceRoots: roots,
    };
  }

  private getLocalResourceRoots(): vscode.Uri[] {
    const roots: vscode.Uri[] = [];
    roots.push(vscode.Uri.joinPath(this.extensionUri, 'media'));

    const workspaces = vscode.workspace.workspaceFolders;
    if (workspaces) {
      for (const ws of workspaces) {
        roots.push(ws.uri);
      }
    }

    return roots;
  }

  private post(msg: ExtToWebview) {
    this._view?.webview.postMessage(msg);
  }

  /** CSP 安全的 HTML */
  private getHtml(webview: vscode.Webview): string {
    const nonce = getNonce();
    const scriptUri = webview.asWebviewUri(
      vscode.Uri.joinPath(this.extensionUri, 'media', 'sidebar.js'),
    );
    const styleUri = webview.asWebviewUri(
      vscode.Uri.joinPath(this.extensionUri, 'media', 'sidebar.css'),
    );
    // Radix 需 unsafe-inline 用于内联定位样式
    const csp = [
      `default-src 'none'`,
      `img-src ${webview.cspSource} https: data:`,
      `style-src ${webview.cspSource} 'unsafe-inline'`,
      `script-src 'nonce-${nonce}'`,
    ].join('; ');

    return `<!DOCTYPE html>
<html lang="zh-CN">
<head>
  <meta charset="UTF-8">
  <meta http-equiv="Content-Security-Policy" content="${csp}">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <link rel="stylesheet" href="${styleUri}">
</head>
<body>
  <div id="root"></div>
  <script nonce="${nonce}" src="${scriptUri}"></script>
</body>
</html>`;
  }
}

function getNonce(): string {
  let text = '';
  const possible = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
  for (let i = 0; i < 64; i++) {
    text += possible.charAt(Math.floor(Math.random() * possible.length));
  }
  return text;
}

input.content:
* { box-sizing: border-box; margin: 0; padding: 0; }

:root {
  --bg: var(--vscode-sideBar-background, #1e1e1e);
  --fg: var(--vscode-sideBar-foreground, #cccccc);
  --border: var(--vscode-sideBar-border, #333);
  --accent: var(--vscode-focusBorder, #007acc);
  --input-bg: var(--vscode-input-background, #3c3c3c);
  --input-fg: var(--vscode-input-foreground, #cccccc);
  --btn-bg: var(--vscode-button-background, #007acc);
  --btn-fg: var(--vscode-button-foreground, #ffffff);
  --btn-secondary-bg: var(--vscode-button-secondaryBackground, #3a3d41);
  --error: #f14c4c;
  --warn: #cca700;
  --success: #4ec94e;
}

body {
  font-family: var(--vscode-font-family);
  font-size: var(--vscode-font-size, 13px);
  color: var(--fg);
  background: var(--bg);
  padding: 0;
}

/* Tabs */
.tab-list {
  display: flex;
  border-bottom: 1px solid var(--border);
}
.tab-trigger {
  flex: 1;
  padding: 6px 8px;
  border: none;
  background: none;
  color: var(--fg);
  cursor: pointer;
  font-size: 12px;
  text-align: center;
  border-bottom: 2px solid transparent;
}
.tab-trigger[data-state="active"] {
  border-bottom-color: var(--accent);
  color: var(--accent);
}
.tab-content {
  padding: 8px;
  overflow-y: auto;
  max-height: calc(100vh - 60px);
}

/* 通用 */
.section-title {
  font-size: 11px;
  text-transform: uppercase;
  color: #888;
  margin: 8px 0 4px;
}
.label {
  font-size: 12px;
  margin-bottom: 2px;
  color: #999;
}
.row {
  display: flex;
  align-items: center;
  gap: 6px;
  margin-bottom: 6px;
}
.grow { flex: 1; }

/* 控件 */
select, input {
  background: var(--input-bg);
  color: var(--input-fg);
  border: 1px solid var(--border);
  padding: 3px 6px;
  font-size: 12px;
  border-radius: 2px;
  outline: none;
}
select:focus, input:focus {
  border-color: var(--accent);
}
select { width: 100%; }
input[type="number"] { width: 50px; text-align: center; }

button {
  background: var(--btn-bg);
  color: var(--btn-fg);
  border: none;
  padding: 4px 10px;
  font-size: 12px;
  border-radius: 2px;
  cursor: pointer;
}
button:hover { opacity: 0.9; }
button:disabled { opacity: 0.5; cursor: default; }
button.secondary {
  background: var(--btn-secondary-bg);
  color: var(--fg);
}
button.small { padding: 2px 6px; font-size: 11px; }
button.danger { background: var(--error); }

/* 状态消息 */
.status-msg { font-size: 12px; padding: 4px 0; }
.status-msg.error { color: var(--error); }
.status-msg.success { color: var(--success); }

/* 素材库 */
.mat-lib {
  margin-bottom: 10px;
  border: 1px solid var(--border);
  border-radius: 4px;
}
.mat-lib-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 4px 8px;
  font-size: 12px;
  background: var(--input-bg);
  cursor: pointer;
}
.mat-lib-body {
  padding: 4px;
}
.mat-grid {
  display: grid;
  gap: 4px;
}
.mat-thumb {
  width: 100%;
  aspect-ratio: 1;
  object-fit: cover;
  cursor: pointer;
  border-radius: 2px;
  border: 1px solid transparent;
}
.mat-thumb:hover { border-color: var(--accent); }

/* 任务卡片 */
.task-card {
  margin-bottom: 8px;
  border: 1px solid var(--border);
  border-radius: 4px;
}
.task-card-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 4px 8px;
  font-size: 12px;
  cursor: pointer;
  background: var(--input-bg);
}
.task-card-body { padding: 6px 8px; }

/* 进度条 */
.progress-bar {
  width: 100%;
  height: 4px;
  background: var(--border);
  border-radius: 2px;
  margin: 4px 0;
}
.progress-fill {
  height: 100%;
  background: var(--accent);
  border-radius: 2px;
  transition: width 0.3s;
}

/* 设置 */
.setting-row {
  margin-bottom: 10px;
}
.setting-row label {
  display: block;
  font-size: 12px;
  margin-bottom: 3px;
  color: #999;
}
.api-key-row {
  display: flex;
  gap: 4px;
}
.api-key-row input { flex: 1; }

/* 注入提示词 */
.injection-editor {
  margin-top: 8px;
}
.injection-editor textarea {
  width: 100%;
  min-height: 60px;
  background: var(--input-bg);
  color: var(--input-fg);
  border: 1px solid var(--border);
  padding: 6px;
  font-size: 12px;
  font-family: var(--vscode-font-family);
  border-radius: 2px;
  resize: vertical;
}

/* 错误列表 */
.error-list {
  font-size: 11px;
  color: var(--error);
  margin-top: 4px;
}
.error-list div { margin-bottom: 2px; }

/* 底部停靠 */
.dock-bottom {
  border-top: 1px solid var(--border);
  padding: 8px;
  margin-top: 8px;
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { createRoot } from 'react-dom/client';
import type {
  ExtToWebview, WebviewToExt, ExtensionConfig,
  TaskInfo, HistoryEntry, MaterialLibrary,
} from '../src/shared';

const vscode = acquireVsCodeApi();

// --- App ---
function App() {
  const [tab, setTab] = useState('workbench');
  const [config, setConfig] = useState<ExtensionConfig | null>(null);
  const [activeFilePath, setActiveFilePath] = useState<string | null>(null);
  const [activeFileName, setActiveFileName] = useState<string | null>(null);
  const [tasks, setTasks] = useState<TaskInfo[]>([]);
  const [history, setHistory] = useState<HistoryEntry[]>([]);
  const [autoLibs, setAutoLibs] = useState<MaterialLibrary[]>([]);
  const [manualLibs, setManualLibs] = useState<MaterialLibrary[]>([]);
  const [statusMsg, setStatusMsg] = useState('');
  const [statusError, setStatusError] = useState(false);
  const [submitting, setSubmitting] = useState(false);

  useEffect(() => {
    const handler = (e: MessageEvent) => {
      const msg = e.data as ExtToWebview;
      switch (msg.type) {
        case 'config':
          setConfig(msg.config);
          break;
        case 'activeMd':
          setActiveFilePath(msg.filePath);
          setActiveFileName(msg.fileName);
          break;
        case 'tasks':
          setTasks(msg.tasks);
          setHistory(msg.history);
          break;
        case 'materials':
          setAutoLibs(msg.auto);
          setManualLibs(msg.manual);
          break;
        case 'status':
          setStatusMsg(msg.message);
          setStatusError(msg.isError);
          setTimeout(() => { setStatusMsg(''); setStatusError(false); }, 5000);
          break;
      }
    };
    window.addEventListener('message', handler);
    // 发 init
    vscode.postMessage({ type: 'init' });
    return () => window.removeEventListener('message', handler);
  }, []);

  // 提交完成后恢复按钮
  useEffect(() => {
    const hasPending = tasks.some((t) =>
      t.jobs.some((j) => j.status === 'running' || j.status === 'submitting'),
    );
    setSubmitting(hasPending);
  }, [tasks]);

  const post = (msg: WebviewToExt) => vscode.postMessage(msg);

  if (!config) return <div style={{ padding: 8 }}>加载中…</div>;

  return (
    <div>
      <div className="tab-list">
        <button className="tab-trigger" data-state={tab === 'workbench' ? 'active' : ''} onClick={() => setTab('workbench')}>工作台</button>
        <button className="tab-trigger" data-state={tab === 'tasks' ? 'active' : ''} onClick={() => setTab('tasks')}>任务</button>
        <button className="tab-trigger" data-state={tab === 'settings' ? 'active' : ''} onClick={() => setTab('settings')}>设置</button>
      </div>

      <div className="tab-content">
        {tab === 'workbench' && (
          <WorkbenchTab
            config={config}
            activeFileName={activeFileName}
            autoLibs={autoLibs}
            manualLibs={manualLibs}
            statusMsg={statusMsg}
            statusError={statusError}
            submitting={submitting}
            post={post}
          />
        )}
        {tab === 'tasks' && (
          <TasksTab
            tasks={tasks}
            history={history}
            tasksCols={config.tasksCols}
            post={post}
          />
        )}
        {tab === 'settings' && (
          <SettingsTab config={config} post={post} />
        )}
      </div>
    </div>
  );
}

// --- 工作台 ---
function WorkbenchTab({
  config, activeFileName, autoLibs, manualLibs,
  statusMsg, statusError, submitting, post,
}: {
  config: ExtensionConfig;
  activeFileName: string | null;
  autoLibs: MaterialLibrary[];
  manualLibs: MaterialLibrary[];
  statusMsg: string;
  statusError: boolean;
  submitting: boolean;
  post: (msg: WebviewToExt) => void;
}) {
  return (
    <div>
      {/* 素材库区 */}
      <MaterialSection
        autoLibs={autoLibs}
        manualLibs={manualLibs}
        workbenchCols={config.workbenchCols}
        post={post}
      />

      {/* 底部停靠区 */}
      <div className="dock-bottom">
        {/* 控件行 */}
        <div className="row">
          <div className="grow">
            <label className="label">模型</label>
            <select value={config.model} onChange={(e) => post({ type: 'saveConfig', key: 'model', value: e.target.value })}>
              <option value="nano-banana-2">nano-banana-2</option>
              <option value="nano-banana-pro">nano-banana-pro</option>
              <option value="gpt-image-2">gpt-image-2</option>
              <option value="gpt-image-2-vip">gpt-image-2-vip</option>
            </select>
          </div>
          <div className="grow">
            <label className="label">分辨率</label>
            <select value={config.imageSize} onChange={(e) => post({ type: 'saveConfig', key: 'imageSize', value: e.target.value })}>
              <option value="1K">1K</option>
              <option value="2K">2K</option>
              <option value="4K">4K</option>
            </select>
          </div>
          <div className="grow">
            <label className="label">比例</label>
            <select value={config.aspectRatio} onChange={(e) => post({ type: 'saveConfig', key: 'aspectRatio', value: e.target.value })}>
              <option value="1:1">1:1</option>
              <option value="16:9">16:9</option>
              <option value="9:16">9:16</option>
              <option value="4:3">4:3</option>
              <option value="3:4">3:4</option>
            </select>
          </div>
          <div>
            <label className="label">并发</label>
            <input type="number" min={1} max={10} value={config.concurrency}
              onChange={(e) => {
                const v = Math.max(1, Math.min(10, parseInt(e.target.value) || 1));
                post({ type: 'saveConfig', key: 'concurrency', value: v });
              }}
            />
          </div>
        </div>

        {/* 生成行 */}
        <div className="row">
          <span style={{ fontSize: 12, flex: 1 }}>
            {activeFileName || '未打开 Markdown 文件'}
          </span>
          <button className="secondary small" onClick={() => post({ type: 'preview' })}>预览请求</button>
          <button className="small" disabled={submitting || !activeFileName} onClick={() => post({ type: 'generate' })}>
            {submitting ? '生成中…' : '生成'}
          </button>
        </div>

        {/* 状态行 */}
        {statusMsg && (
          <div className={`status-msg ${statusError ? 'error' : 'success'}`}>{statusMsg}</div>
        )}
      </div>
    </div>
  );
}

// --- 素材库区 ---
function MaterialSection({
  autoLibs, manualLibs, workbenchCols, post,
}: {
  autoLibs: MaterialLibrary[];
  manualLibs: MaterialLibrary[];
  workbenchCols: number;
  post: (msg: WebviewToExt) => void;
}) {
  const [expanded, setExpanded] = useState<Record<string, boolean>>({});

  const toggleExpand = (name: string) => {
    setExpanded((prev) => ({ ...prev, [name]: !prev[name] }));
  };

  return (
    <div>
      <div className="section-title">当前路径</div>
      {autoLibs.map((lib) => (
        <MaterialLib
          key={lib.name}
          lib={lib}
          cols={workbenchCols}
          expanded={expanded[lib.name] !== false}
          onToggle={() => toggleExpand(lib.name)}
          post={post}
        />
      ))}

      <div className="section-title">手动素材库</div>
      {manualLibs.map((lib) => (
        <MaterialLib
          key={lib.path}
          lib={lib}
          cols={workbenchCols}
          expanded={expanded[lib.path] !== false}
          onToggle={() => toggleExpand(lib.path)}
          post={post}
          removable
        />
      ))}
      <button className="small secondary" style={{ marginTop: 4 }}
        onClick={() => post({ type: 'addMaterialDir' })}>
        + 添加
      </button>
    </div>
  );
}

function MaterialLib({
  lib, cols, expanded, onToggle, post, removable,
}: {
  lib: MaterialLibrary;
  cols: number;
  expanded: boolean;
  onToggle: () => void;
  post: (msg: WebviewToExt) => void;
  removable?: boolean;
}) {
  return (
    <div className="mat-lib">
      <div className="mat-lib-header" onClick={onToggle}>
        <span>{lib.name} ({lib.images.length})</span>
        <span style={{ display: 'flex', gap: 4 }}>
          {expanded ? '▾' : '▸'}
          {removable && (
            <button className="small danger" onClick={(e) => {
              e.stopPropagation();
              post({ type: 'removeMaterialDir', dir: lib.path });
            }}>×</button>
          )}
        </span>
      </div>
      {expanded && lib.images.length > 0 && (
        <div className="mat-lib-body">
          <div className="mat-grid" style={{ gridTemplateColumns: `repeat(${cols}, 1fr)` }}>
            {lib.images.map((img) => (
              <img
                key={img.path}
                className="mat-thumb"
                src={img.webviewUri}
                title={img.name}
                onClick={() => post({ type: 'openImage', imagePath: img.path })}
                onContextMenu={(e) => {
                  e.preventDefault();
                  post({ type: 'insertImage', imagePath: img.path });
                }}
              />
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

// --- 任务页 ---
function TasksTab({
  tasks, history, tasksCols, post,
}: {
  tasks: TaskInfo[];
  history: HistoryEntry[];
  tasksCols: number;
  post: (msg: WebviewToExt) => void;
}) {
  return (
    <div>
      {/* 进行中任务与历史合并倒序：进行中在前 */}
      {tasks.map((task) => (
        <InProgressCard key={task.id} task={task} cols={tasksCols} post={post} />
      ))}
      {tasks.length === 0 && history.length === 0 && (
        <div style={{ fontSize: 12, color: '#888', padding: 16, textAlign: 'center' }}>
          暂无任务
        </div>
      )}
      {history.map((entry) => (
        <HistoryCard key={entry.folderName} entry={entry} cols={tasksCols} post={post} />
      ))}
    </div>
  );
}

function InProgressCard({ task, cols, post }: { task: TaskInfo; cols: number; post: (msg: WebviewToExt) => void }) {
  const [expanded, setExpanded] = useState(true);
  const [elapsed, setElapsed] = useState('');

  const totalJobs = task.jobs.length;
  const doneJobs = task.jobs.filter((j) => j.status === 'succeeded' || j.status === 'failed' || j.status === 'violation').length;
  const runningJobs = task.jobs.filter((j) => j.status === 'running').length;
  const submittingJobs = task.jobs.filter((j) => j.status === 'submitting').length;
  const failedJobs = task.jobs.filter((j) => j.status === 'failed' || j.status === 'violation').length;

  // 聚合进度
  const progress = task.jobs.reduce((sum, j) => {
    if (j.status === 'succeeded' || j.status === 'failed' || j.status === 'violation') return sum + 100;
    if (j.status === 'running') return sum + (j.progress || 0);
    return sum;
  }, 0) / totalJobs;

  const allImages = task.jobs.flatMap((j) => j.images);
  const errors = task.jobs.filter((j) => j.error).map((j) => j.error!);

  // 计时器
  useEffect(() => {
    const timer = setInterval(() => {
      const delta = Math.floor((Date.now() - task.startedAt) / 1000);
      const h = Math.floor(delta / 3600);
      const m = Math.floor((delta % 3600) / 60);
      const s = delta % 60;
      if (h > 0) {
        setElapsed(`${h}:${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}`);
      } else {
        setElapsed(`${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}`);
      }
    }, 1000);
    return () => clearInterval(timer);
  }, [task.startedAt]);

  return (
    <div className="task-card">
      <div className="task-card-header" onClick={() => setExpanded(!expanded)}>
        <span>
          {task.folderName}（{task.model}）·
          {submittingJobs > 0 ? ` 提交中 ${doneJobs}/${totalJobs}` : ` 生成中 ${doneJobs}/${totalJobs}`}
          {failedJobs > 0 ? ` · 失败 ${failedJobs}` : ''} · {elapsed}
        </span>
        <span>{expanded ? '▾' : '▸'}</span>
      </div>
      {expanded && (
        <div className="task-card-body">
          <div className="progress-bar">
            <div className="progress-fill" style={{ width: `${Math.round(progress)}%` }} />
          </div>
          <div style={{ fontSize: 11, color: '#888', marginBottom: 4 }}>{Math.round(progress)}%</div>

          {submittingJobs > 0 && <div style={{ fontSize: 11 }}>正在提交 {submittingJobs} 个请求…</div>}
          {runningJobs > 0 && <div style={{ fontSize: 11 }}>还有 {runningJobs} 张正在生成…</div>}

          {allImages.length > 0 && (
            <div className="mat-grid" style={{ gridTemplateColumns: `repeat(${cols}, 1fr)`, marginTop: 6 }}>
              {allImages.map((img, i) => (
                <img key={i} className="mat-thumb"
                  src={postImgUri(task.folderPath, img)}
                  onClick={() => post({ type: 'openImage', imagePath: `${task.folderPath}/${img}` })}
                />
              ))}
            </div>
          )}

          {errors.length > 0 && (
            <div className="error-list">
              {errors.map((err, i) => <div key={i}>{err}</div>)}
            </div>
          )}
        </div>
      )}
    </div>
  );
}

function HistoryCard({ entry, cols, post }: { entry: HistoryEntry; cols: number; post: (msg: WebviewToExt) => void }) {
  const [expanded, setExpanded] = useState(false);
  return (
    <div className="task-card">
      <div className="task-card-header" onClick={() => setExpanded(!expanded)}>
        <span>{entry.folderName}（{entry.imageCount} 张）</span>
        <span>{expanded ? '▾' : '▸'}</span>
      </div>
      {expanded && (
        <div className="task-card-body">
          <div className="mat-grid" style={{ gridTemplateColumns: `repeat(${cols}, 1fr)` }}>
            {entry.images.map((img, i) => (
              <img key={i} className="mat-thumb"
                src={postImgUri(entry.folderPath, img)}
                onClick={() => post({ type: 'openImage', imagePath: `${entry.folderPath}/${img}` })}
              />
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

// helper: 构建图片 URI（webview 内需要通过 vscode URI scheme 显示本地图片）
function postImgUri(folderPath: string, fileName: string): string {
  // 在侧栏中，图片 URI 需要经扩展转换；这里传原始路径，由扩展先转换再传回
  // 但任务卡片中图片已通过 getHistory 返回的 images 只是文件名
  // 实际需要通过 postMessage 转换
  return `vscode-webview-resource:${folderPath}/${fileName}`;
}

// --- 设置页 ---
function SettingsTab({ config, post }: { config: ExtensionConfig; post: (msg: WebviewToExt) => void }) {
  const [apiKeyInput, setApiKeyInput] = useState('');
  const [injectionModel, setInjectionModel] = useState(config.model);
  const showApiKey = config.apiKey === '***';

  const currentInjection = config.modelInjections[injectionModel] || '';

  return (
    <div>
      {/* API Key */}
      <div className="setting-row">
        <label>API Key {showApiKey ? '(已保存)' : ''}</label>
        <div className="api-key-row">
          <input
            type="password"
            placeholder={showApiKey ? '已保存' : '输入 API Key'}
            value={apiKeyInput}
            onChange={(e) => setApiKeyInput(e.target.value)}
          />
          <button className="small" onClick={() => {
            if (apiKeyInput.trim()) {
              post({ type: 'setApiKey', value: apiKeyInput.trim() });
              setApiKeyInput('');
            }
          }}>保存</button>
        </div>
        <a
          href="#"
          onClick={(e) => { e.preventDefault(); post({ type: 'openUrl', url: 'https://grsai.ai/zh/dashboard/api-keys' }); }}
          style={{ fontSize: 11, color: 'var(--accent)' }}
        >
          获取 API Key →
        </a>
      </div>

      {/* 节点 */}
      <div className="setting-row">
        <label>API 节点</label>
        <select value={config.baseUrl} onChange={(e) => post({ type: 'saveConfig', key: 'baseUrl', value: e.target.value })}>
          <option value="https://grsai.dakka.com.cn">国内节点</option>
          <option value="https://grsaiapi.com">全球节点</option>
        </select>
      </div>

      {/* 每行张数 */}
      <div className="row">
        <div className="grow">
          <label className="label">工作台每行</label>
          <input type="number" min={1} max={8} value={config.workbenchCols}
            onChange={(e) => post({ type: 'saveConfig', key: 'workbenchCols', value: Math.max(1, Math.min(8, parseInt(e.target.value) || 1)) })}
          />
        </div>
        <div className="grow">
          <label className="label">任务栏每行</label>
          <input type="number" min={1} max={8} value={config.tasksCols}
            onChange={(e) => post({ type: 'saveConfig', key: 'tasksCols', value: Math.max(1, Math.min(8, parseInt(e.target.value) || 1)) })}
          />
        </div>
      </div>

      {/* 模型注入提示词 */}
      <div className="injection-editor">
        <label className="label">模型注入提示词</label>
        <select value={injectionModel} onChange={(e) => setInjectionModel(e.target.value)}>
          <option value="nano-banana-2">nano-banana-2</option>
          <option value="nano-banana-pro">nano-banana-pro</option>
          <option value="gpt-image-2">gpt-image-2</option>
          <option value="gpt-image-2-vip">gpt-image-2-vip</option>
        </select>
        <textarea
          value={currentInjection}
          onChange={(e) => {
            const newInjections = { ...config.modelInjections, [injectionModel]: e.target.value };
            post({ type: 'saveConfig', key: 'modelInjections', value: newInjections });
          }}
          placeholder="输入注入提示词…"
        />
      </div>
    </div>
  );
}

// --- 启动 ---
const root = createRoot(document.getElementById('root')!);
root.render(<App />);

toolUseResult.content:
* { box-sizing: border-box; margin: 0; padding: 0; }

:root {
  --bg: var(--vscode-sideBar-background, #1e1e1e);
  --fg: var(--vscode-sideBar-foreground, #cccccc);
  --border: var(--vscode-sideBar-border, #333);
  --accent: var(--vscode-focusBorder, #007acc);
  --input-bg: var(--vscode-input-background, #3c3c3c);
  --input-fg: var(--vscode-input-foreground, #cccccc);
  --btn-bg: var(--vscode-button-background, #007acc);
  --btn-fg: var(--vscode-button-foreground, #ffffff);
  --btn-secondary-bg: var(--vscode-button-secondaryBackground, #3a3d41);
  --error: #f14c4c;
  --warn: #cca700;
  --success: #4ec94e;
}

body {
  font-family: var(--vscode-font-family);
  font-size: var(--vscode-font-size, 13px);
  color: var(--fg);
  background: var(--bg);
  padding: 0;
}

/* Tabs */
.tab-list {
  display: flex;
  border-bottom: 1px solid var(--border);
}
.tab-trigger {
  flex: 1;
  padding: 6px 8px;
  border: none;
  background: none;
  color: var(--fg);
  cursor: pointer;
  font-size: 12px;
  text-align: center;
  border-bottom: 2px solid transparent;
}
.tab-trigger[data-state="active"] {
  border-bottom-color: var(--accent);
  color: var(--accent);
}
.tab-content {
  padding: 8px;
  overflow-y: auto;
  max-height: calc(100vh - 60px);
}

/* 通用 */
.section-title {
  font-size: 11px;
  text-transform: uppercase;
  color: #888;
  margin: 8px 0 4px;
}
.label {
  font-size: 12px;
  margin-bottom: 2px;
  color: #999;
}
.row {
  display: flex;
  align-items: center;
  gap: 6px;
  margin-bottom: 6px;
}
.grow { flex: 1; }

/* 控件 */
select, input {
  background: var(--input-bg);
  color: var(--input-fg);
  border: 1px solid var(--border);
  padding: 3px 6px;
  font-size: 12px;
  border-radius: 2px;
  outline: none;
}
select:focus, input:focus {
  border-color: var(--accent);
}
select { width: 100%; }
input[type="number"] { width: 50px; text-align: center; }

button {
  background: var(--btn-bg);
  color: var(--btn-fg);
  border: none;
  padding: 4px 10px;
  font-size: 12px;
  border-radius: 2px;
  cursor: pointer;
}
button:hover { opacity: 0.9; }
button:disabled { opacity: 0.5; cursor: default; }
button.secondary {
  background: var(--btn-secondary-bg);
  color: var(--fg);
}
button.small { padding: 2px 6px; font-size: 11px; }
button.danger { background: var(--error); }

/* 状态消息 */
.status-msg { font-size: 12px; padding: 4px 0; }
.status-msg.error { color: var(--error); }
.status-msg.success { color: var(--success); }

/* 素材库 */
.mat-lib {
  margin-bottom: 10px;
  border: 1px solid var(--border);
  border-radius: 4px;
}
.mat-lib-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 4px 8px;
  font-size: 12px;
  background: var(--input-bg);
  cursor: pointer;
}
.mat-lib-body {
  padding: 4px;
}
.mat-grid {
  display: grid;
  gap: 4px;
}
.mat-thumb {
  width: 100%;
  aspect-ratio: 1;
  object-fit: cover;
  cursor: pointer;
  border-radius: 2px;
  border: 1px solid transparent;
}
.mat-thumb:hover { border-color: var(--accent); }

/* 任务卡片 */
.task-card {
  margin-bottom: 8px;
  border: 1px solid var(--border);
  border-radius: 4px;
}
.task-card-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 4px 8px;
  font-size: 12px;
  cursor: pointer;
  background: var(--input-bg);
}
.task-card-body { padding: 6px 8px; }

/* 进度条 */
.progress-bar {
  width: 100%;
  height: 4px;
  background: var(--border);
  border-radius: 2px;
  margin: 4px 0;
}
.progress-fill {
  height: 100%;
  background: var(--accent);
  border-radius: 2px;
  transition: width 0.3s;
}

/* 设置 */
.setting-row {
  margin-bottom: 10px;
}
.setting-row label {
  display: block;
  font-size: 12px;
  margin-bottom: 3px;
  color: #999;
}
.api-key-row {
  display: flex;
  gap: 4px;
}
.api-key-row input { flex: 1; }

/* 注入提示词 */
.injection-editor {
  margin-top: 8px;
}
.injection-editor textarea {
  width: 100%;
  min-height: 60px;
  background: var(--input-bg);
  color: var(--input-fg);
  border: 1px solid var(--border);
  padding: 6px;
  font-size: 12px;
  font-family: var(--vscode-font-family);
  border-radius: 2px;
  resize: vertical;
}

/* 错误列表 */
.error-list {
  font-size: 11px;
  color: var(--error);
  margin-top: 4px;
}
.error-list div { margin-bottom: 2px; }

/* 底部停靠 */
.dock-bottom {
  border-top: 1px solid var(--border);
  padding: 8px;
  margin-top: 8px;
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { createRoot } from 'react-dom/client';
import type {
  ExtToWebview, WebviewToExt, ExtensionConfig,
  TaskInfo, HistoryEntry, MaterialLibrary,
} from '../src/shared';

const vscode = acquireVsCodeApi();

// --- App ---
function App() {
  const [tab, setTab] = useState('workbench');
  const [config, setConfig] = useState<ExtensionConfig | null>(null);
  const [activeFilePath, setActiveFilePath] = useState<string | null>(null);
  const [activeFileName, setActiveFileName] = useState<string | null>(null);
  const [tasks, setTasks] = useState<TaskInfo[]>([]);
  const [history, setHistory] = useState<HistoryEntry[]>([]);
  const [autoLibs, setAutoLibs] = useState<MaterialLibrary[]>([]);
  const [manualLibs, setManualLibs] = useState<MaterialLibrary[]>([]);
  const [statusMsg, setStatusMsg] = useState('');
  const [statusError, setStatusError] = useState(false);
  const [submitting, setSubmitting] = useState(false);

  useEffect(() => {
    const handler = (e: MessageEvent) => {
      const msg = e.data as ExtToWebview;
      switch (msg.type) {
        case 'config':
          setConfig(msg.config);
          break;
        case 'activeMd':
          setActiveFilePath(msg.filePath);
          setActiveFileName(msg.fileName);
          break;
        case 'tasks':
          setTasks(msg.tasks);
          setHistory(msg.history);
          break;
        case 'materials':
          setAutoLibs(msg.auto);
          setManualLibs(msg.manual);
          break;
        case 'status':
          setStatusMsg(msg.message);
          setStatusError(msg.isError);
          setTimeout(() => { setStatusMsg(''); setStatusError(false); }, 5000);
          break;
      }
    };
    window.addEventListener('message', handler);
    // 发 init
    vscode.postMessage({ type: 'init' });
    return () => window.removeEventListener('message', handler);
  }, []);

  // 提交完成后恢复按钮
  useEffect(() => {
    const hasPending = tasks.some((t) =>
      t.jobs.some((j) => j.status === 'running' || j.status === 'submitting'),
    );
    setSubmitting(hasPending);
  }, [tasks]);

  const post = (msg: WebviewToExt) => vscode.postMessage(msg);

  if (!config) return <div style={{ padding: 8 }}>加载中…</div>;

  return (
    <div>
      <div className="tab-list">
        <button className="tab-trigger" data-state={tab === 'workbench' ? 'active' : ''} onClick={() => setTab('workbench')}>工作台</button>
        <button className="tab-trigger" data-state={tab === 'tasks' ? 'active' : ''} onClick={() => setTab('tasks')}>任务</button>
        <button className="tab-trigger" data-state={tab === 'settings' ? 'active' : ''} onClick={() => setTab('settings')}>设置</button>
      </div>

      <div className="tab-content">
        {tab === 'workbench' && (
          <WorkbenchTab
            config={config}
            activeFileName={activeFileName}
            autoLibs={autoLibs}
            manualLibs={manualLibs}
            statusMsg={statusMsg}
            statusError={statusError}
            submitting={submitting}
            post={post}
          />
        )}
        {tab === 'tasks' && (
          <TasksTab
            tasks={tasks}
            history={history}
            tasksCols={config.tasksCols}
            post={post}
          />
        )}
        {tab === 'settings' && (
          <SettingsTab config={config} post={post} />
        )}
      </div>
    </div>
  );
}

// --- 工作台 ---
function WorkbenchTab({
  config, activeFileName, autoLibs, manualLibs,
  statusMsg, statusError, submitting, post,
}: {
  config: ExtensionConfig;
  activeFileName: string | null;
  autoLibs: MaterialLibrary[];
  manualLibs: MaterialLibrary[];
  statusMsg: string;
  statusError: boolean;
  submitting: boolean;
  post: (msg: WebviewToExt) => void;
}) {
  return (
    <div>
      {/* 素材库区 */}
      <MaterialSection
        autoLibs={autoLibs}
        manualLibs={manualLibs}
        workbenchCols={config.workbenchCols}
        post={post}
      />

      {/* 底部停靠区 */}
      <div className="dock-bottom">
        {/* 控件行 */}
        <div className="row">
          <div className="grow">
            <label className="label">模型</label>
            <select value={config.model} onChange={(e) => post({ type: 'saveConfig', key: 'model', value: e.target.value })}>
              <option value="nano-banana-2">nano-banana-2</option>
              <option value="nano-banana-pro">nano-banana-pro</option>
              <option value="gpt-image-2">gpt-image-2</option>
              <option value="gpt-image-2-vip">gpt-image-2-vip</option>
            </select>
          </div>
          <div className="grow">
            <label className="label">分辨率</label>
            <select value={config.imageSize} onChange={(e) => post({ type: 'saveConfig', key: 'imageSize', value: e.target.value })}>
              <option value="1K">1K</option>
              <option value="2K">2K</option>
              <option value="4K">4K</option>
            </select>
          </div>
          <div className="grow">
            <label className="label">比例</label>
            <select value={config.aspectRatio} onChange={(e) => post({ type: 'saveConfig', key: 'aspectRatio', value: e.target.value })}>
              <option value="1:1">1:1</option>
              <option value="16:9">16:9</option>
              <option value="9:16">9:16</option>
              <option value="4:3">4:3</option>
              <option value="3:4">3:4</option>
            </select>
          </div>
          <div>
            <label className="label">并发</label>
            <input type="number" min={1} max={10} value={config.concurrency}
              onChange={(e) => {
                const v = Math.max(1, Math.min(10, parseInt(e.target.value) || 1));
                post({ type: 'saveConfig', key: 'concurrency', value: v });
              }}
            />
          </div>
        </div>

        {/* 生成行 */}
        <div className="row">
          <span style={{ fontSize: 12, flex: 1 }}>
            {activeFileName || '未打开 Markdown 文件'}
          </span>
          <button className="secondary small" onClick={() => post({ type: 'preview' })}>预览请求</button>
          <button className="small" disabled={submitting || !activeFileName} onClick={() => post({ type: 'generate' })}>
            {submitting ? '生成中…' : '生成'}
          </button>
        </div>

        {/* 状态行 */}
        {statusMsg && (
          <div className={`status-msg ${statusError ? 'error' : 'success'}`}>{statusMsg}</div>
        )}
      </div>
    </div>
  );
}

// --- 素材库区 ---
function MaterialSection({
  autoLibs, manualLibs, workbenchCols, post,
}: {
  autoLibs: MaterialLibrary[];
  manualLibs: MaterialLibrary[];
  workbenchCols: number;
  post: (msg: WebviewToExt) => void;
}) {
  const [expanded, setExpanded] = useState<Record<string, boolean>>({});

  const toggleExpand = (name: string) => {
    setExpanded((prev) => ({ ...prev, [name]: !prev[name] }));
  };

  return (
    <div>
      <div className="section-title">当前路径</div>
      {autoLibs.map((lib) => (
        <MaterialLib
          key={lib.name}
          lib={lib}
          cols={workbenchCols}
          expanded={expanded[lib.name] !== false}
          onToggle={() => toggleExpand(lib.name)}
          post={post}
        />
      ))}

      <div className="section-title">手动素材库</div>
      {manualLibs.map((lib) => (
        <MaterialLib
          key={lib.path}
          lib={lib}
          cols={workbenchCols}
          expanded={expanded[lib.path] !== false}
          onToggle={() => toggleExpand(lib.path)}
          post={post}
          removable
        />
      ))}
      <button className="small secondary" style={{ marginTop: 4 }}
        onClick={() => post({ type: 'addMaterialDir' })}>
        + 添加
      </button>
    </div>
  );
}

function MaterialLib({
  lib, cols, expanded, onToggle, post, removable,
}: {
  lib: MaterialLibrary;
  cols: number;
  expanded: boolean;
  onToggle: () => void;
  post: (msg: WebviewToExt) => void;
  removable?: boolean;
}) {
  return (
    <div className="mat-lib">
      <div className="mat-lib-header" onClick={onToggle}>
        <span>{lib.name} ({lib.images.length})</span>
        <span style={{ display: 'flex', gap: 4 }}>
          {expanded ? '▾' : '▸'}
          {removable && (
            <button className="small danger" onClick={(e) => {
              e.stopPropagation();
              post({ type: 'removeMaterialDir', dir: lib.path });
            }}>×</button>
          )}
        </span>
      </div>
      {expanded && lib.images.length > 0 && (
        <div className="mat-lib-body">
          <div className="mat-grid" style={{ gridTemplateColumns: `repeat(${cols}, 1fr)` }}>
            {lib.images.map((img) => (
              <img
                key={img.path}
                className="mat-thumb"
                src={img.webviewUri}
                title={img.name}
                onClick={() => post({ type: 'openImage', imagePath: img.path })}
                onContextMenu={(e) => {
                  e.preventDefault();
                  post({ type: 'insertImage', imagePath: img.path });
                }}
              />
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

// --- 任务页 ---
function TasksTab({
  tasks, history, tasksCols, post,
}: {
  tasks: TaskInfo[];
  history: HistoryEntry[];
  tasksCols: number;
  post: (msg: WebviewToExt) => void;
}) {
  return (
    <div>
      {/* 进行中任务与历史合并倒序：进行中在前 */}
      {tasks.map((task) => (
        <InProgressCard key={task.id} task={task} cols={tasksCols} post={post} />
      ))}
      {tasks.length === 0 && history.length === 0 && (
        <div style={{ fontSize: 12, color: '#888', padding: 16, textAlign: 'center' }}>
          暂无任务
        </div>
      )}
      {history.map((entry) => (
        <HistoryCard key={entry.folderName} entry={entry} cols={tasksCols} post={post} />
      ))}
    </div>
  );
}

function InProgressCard({ task, cols, post }: { task: TaskInfo; cols: number; post: (msg: WebviewToExt) => void }) {
  const [expanded, setExpanded] = useState(true);
  const [elapsed, setElapsed] = useState('');

  const totalJobs = task.jobs.length;
  const doneJobs = task.jobs.filter((j) => j.status === 'succeeded' || j.status === 'failed' || j.status === 'violation').length;
  const runningJobs = task.jobs.filter((j) => j.status === 'running').length;
  const submittingJobs = task.jobs.filter((j) => j.status === 'submitting').length;
  const failedJobs = task.jobs.filter((j) => j.status === 'failed' || j.status === 'violation').length;

  // 聚合进度
  const progress = task.jobs.reduce((sum, j) => {
    if (j.status === 'succeeded' || j.status === 'failed' || j.status === 'violation') return sum + 100;
    if (j.status === 'running') return sum + (j.progress || 0);
    return sum;
  }, 0) / totalJobs;

  const allImages = task.jobs.flatMap((j) => j.images);
  const errors = task.jobs.filter((j) => j.error).map((j) => j.error!);

  // 计时器
  useEffect(() => {
    const timer = setInterval(() => {
      const delta = Math.floor((Date.now() - task.startedAt) / 1000);
      const h = Math.floor(delta / 3600);
      const m = Math.floor((delta % 3600) / 60);
      const s = delta % 60;
      if (h > 0) {
        setElapsed(`${h}:${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}`);
      } else {
        setElapsed(`${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}`);
      }
    }, 1000);
    return () => clearInterval(timer);
  }, [task.startedAt]);

  return (
    <div className="task-card">
      <div className="task-card-header" onClick={() => setExpanded(!expanded)}>
        <span>
          {task.folderName}（{task.model}）·
          {submittingJobs > 0 ? ` 提交中 ${doneJobs}/${totalJobs}` : ` 生成中 ${doneJobs}/${totalJobs}`}
          {failedJobs > 0 ? ` · 失败 ${failedJobs}` : ''} · {elapsed}
        </span>
        <span>{expanded ? '▾' : '▸'}</span>
      </div>
      {expanded && (
        <div className="task-card-body">
          <div className="progress-bar">
            <div className="progress-fill" style={{ width: `${Math.round(progress)}%` }} />
          </div>
          <div style={{ fontSize: 11, color: '#888', marginBottom: 4 }}>{Math.round(progress)}%</div>

          {submittingJobs > 0 && <div style={{ fontSize: 11 }}>正在提交 {submittingJobs} 个请求…</div>}
          {runningJobs > 0 && <div style={{ fontSize: 11 }}>还有 {runningJobs} 张正在生成…</div>}

          {allImages.length > 0 && (
            <div className="mat-grid" style={{ gridTemplateColumns: `repeat(${cols}, 1fr)`, marginTop: 6 }}>
              {allImages.map((img, i) => (
                <img key={i} className="mat-thumb"
                  src={postImgUri(task.folderPath, img)}
                  onClick={() => post({ type: 'openImage', imagePath: `${task.folderPath}/${img}` })}
                />
              ))}
            </div>
          )}

          {errors.length > 0 && (
            <div className="error-list">
              {errors.map((err, i) => <div key={i}>{err}</div>)}
            </div>
          )}
        </div>
      )}
    </div>
  );
}

function HistoryCard({ entry, cols, post }: { entry: HistoryEntry; cols: number; post: (msg: WebviewToExt) => void }) {
  const [expanded, setExpanded] = useState(false);
  return (
    <div className="task-card">
      <div className="task-card-header" onClick={() => setExpanded(!expanded)}>
        <span>{entry.folderName}（{entry.imageCount} 张）</span>
        <span>{expanded ? '▾' : '▸'}</span>
      </div>
      {expanded && (
        <div className="task-card-body">
          <div className="mat-grid" style={{ gridTemplateColumns: `repeat(${cols}, 1fr)` }}>
            {entry.images.map((img, i) => (
              <img key={i} className="mat-thumb"
                src={postImgUri(entry.folderPath, img)}
                onClick={() => post({ type: 'openImage', imagePath: `${entry.folderPath}/${img}` })}
              />
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

// helper: 构建图片 URI（webview 内需要通过 vscode URI scheme 显示本地图片）
function postImgUri(folderPath: string, fileName: string): string {
  // 在侧栏中，图片 URI 需要经扩展转换；这里传原始路径，由扩展先转换再传回
  // 但任务卡片中图片已通过 getHistory 返回的 images 只是文件名
  // 实际需要通过 postMessage 转换
  return `vscode-webview-resource:${folderPath}/${fileName}`;
}

// --- 设置页 ---
function SettingsTab({ config, post }: { config: ExtensionConfig; post: (msg: WebviewToExt) => void }) {
  const [apiKeyInput, setApiKeyInput] = useState('');
  const [injectionModel, setInjectionModel] = useState(config.model);
  const showApiKey = config.apiKey === '***';

  const currentInjection = config.modelInjections[injectionModel] || '';

  return (
    <div>
      {/* API Key */}
      <div className="setting-row">
        <label>API Key {showApiKey ? '(已保存)' : ''}</label>
        <div className="api-key-row">
          <input
            type="password"
            placeholder={showApiKey ? '已保存' : '输入 API Key'}
            value={apiKeyInput}
            onChange={(e) => setApiKeyInput(e.target.value)}
          />
          <button className="small" onClick={() => {
            if (apiKeyInput.trim()) {
              post({ type: 'setApiKey', value: apiKeyInput.trim() });
              setApiKeyInput('');
            }
          }}>保存</button>
        </div>
        <a
          href="#"
          onClick={(e) => { e.preventDefault(); post({ type: 'openUrl', url: 'https://grsai.ai/zh/dashboard/api-keys' }); }}
          style={{ fontSize: 11, color: 'var(--accent)' }}
        >
          获取 API Key →
        </a>
      </div>

      {/* 节点 */}
      <div className="setting-row">
        <label>API 节点</label>
        <select value={config.baseUrl} onChange={(e) => post({ type: 'saveConfig', key: 'baseUrl', value: e.target.value })}>
          <option value="https://grsai.dakka.com.cn">国内节点</option>
          <option value="https://grsaiapi.com">全球节点</option>
        </select>
      </div>

      {/* 每行张数 */}
      <div className="row">
        <div className="grow">
          <label className="label">工作台每行</label>
          <input type="number" min={1} max={8} value={config.workbenchCols}
            onChange={(e) => post({ type: 'saveConfig', key: 'workbenchCols', value: Math.max(1, Math.min(8, parseInt(e.target.value) || 1)) })}
          />
        </div>
        <div className="grow">
          <label className="label">任务栏每行</label>
          <input type="number" min={1} max={8} value={config.tasksCols}
            onChange={(e) => post({ type: 'saveConfig', key: 'tasksCols', value: Math.max(1, Math.min(8, parseInt(e.target.value) || 1)) })}
          />
        </div>
      </div>

      {/* 模型注入提示词 */}
      <div className="injection-editor">
        <label className="label">模型注入提示词</label>
        <select value={injectionModel} onChange={(e) => setInjectionModel(e.target.value)}>
          <option value="nano-banana-2">nano-banana-2</option>
          <option value="nano-banana-pro">nano-banana-pro</option>
          <option value="gpt-image-2">gpt-image-2</option>
          <option value="gpt-image-2-vip">gpt-image-2-vip</option>
        </select>
        <textarea
          value={currentInjection}
          onChange={(e) => {
            const newInjections = { ...config.modelInjections, [injectionModel]: e.target.value };
            post({ type: 'saveConfig', key: 'modelInjections', value: newInjections });
          }}
          placeholder="输入注入提示词…"
        />
      </div>
    </div>
  );
}

// --- 启动 ---
const root = createRoot(document.getElementById('root')!);
root.render(<App />);

