  | GenerateMsg
  | PreviewMsg
  | SaveConfigMsg
  | SetApiKeyMsg
  | AddMaterialDirMsg
  | RemoveMaterialDirMsg
  | InsertImageMsg
  | OpenImageMsg
  | OpenUrlMsg;

// --- 配置 ---

export interface ExtensionConfig {
  apiKey: string;
  baseUrl: string;
  model: string;
  aspectRatio: string;
  imageSize: string;
  concurrency: number;
  workbenchCols: number;
  tasksCols: number;
  modelInjections: Record<string, string>;
}

// --- 任务 ---

export type JobStatus = 'submitting' | 'running' | 'succeeded' | 'failed' | 'violation';

export interface JobState {
  index: number;
  id: string | null;
  status: JobStatus;
  progress: number;
