    const parts = u.pathname.split('/');
    const last = parts[parts.length - 1] || '';
    const clean = last.split('?')[0];
    const dotIdx = clean.lastIndexOf('.');
    if (dotIdx >= 0) {
      return clean.slice(dotIdx + 1).toLowerCase();
    }
    return '';
  } catch {
    return '';
  }
}

