import * as assert from 'assert';
import { parseMarkdown, mimeFromExt } from '../src/parser';

suite('parseMarkdown', () => {

  test('普通路径图片语法替换', () => {
    const result = parseMarkdown('![cat](cat.png)', '/test/dir');
    assert.strictEqual(result.body, '[image1](cat)');
    assert.strictEqual(result.refImages.length, 1);
    assert.strictEqual(result.refImages[0].index, 1);
    assert.strictEqual(result.refImages[0].originalPath, 'cat.png');
  });

  test('尖括号路径（含空格）', () => {
    const result = parseMarkdown('![dog](<my dog.png>)', '/test/dir');
    assert.strictEqual(result.body, '[image1](my dog)');
    assert.strictEqual(result.refImages.length, 1);
    assert.strictEqual(result.refImages[0].originalPath, 'my dog.png');
  });

  test('尖括号路径（含括号）', () => {
    const result = parseMarkdown('![pic](<image (1).png>)', '/test/dir');
    assert.strictEqual(result.refImages[0].originalPath, 'image (1).png');
  });

  test('重复引用复用同一编号', () => {
    const content = '![a](cat.png) ![b](cat.png) ![c](dog.png)';
    const result = parseMarkdown(content, '/test/dir');
    // cat.png 首次出现 → image1, 第二次复用 image1; dog.png → image2
    // 替换: [image1](cat) [image1](cat) [image2](dog)
    const expected = '[image1](cat) [image1](cat) [image2](dog)';
    assert.strictEqual(result.body, expected);
    assert.strictEqual(result.refImages.length, 2);
  });

  test('编号与引用数组顺序一致', () => {
    const content = '![a](a.png) ![b](b.png) ![c](c.png)';
    const result = parseMarkdown(content, '/test/dir');
    assert.strictEqual(result.refImages[0].index, 1);
    assert.strictEqual(result.refImages[0].originalPath, 'a.png');
    assert.strictEqual(result.refImages[1].index, 2);
    assert.strictEqual(result.refImages[1].originalPath, 'b.png');
    assert.strictEqual(result.refImages[2].index, 3);
    assert.strictEqual(result.refImages[2].originalPath, 'c.png');
  });

  test('data URI 格式正确', () => {
    const result = parseMarkdown('![a](cat.png)', '/test/dir');
    assert.ok(result.refImages[0].dataUri.startsWith('data:image/'));
    assert.ok(result.refImages[0].dataUri.includes(';base64,'));
  });

});

suite('mimeFromExt', () => {
  test('已知扩展名返回正确 MIME', () => {
    assert.strictEqual(mimeFromExt('png'), 'image/png');
    assert.strictEqual(mimeFromExt('jpg'), 'image/jpeg');
    assert.strictEqual(mimeFromExt('jpeg'), 'image/jpeg');
    assert.strictEqual(mimeFromExt('gif'), 'image/gif');
    assert.strictEqual(mimeFromExt('webp'), 'image/webp');
    assert.strictEqual(mimeFromExt('svg'), 'image/svg+xml');
  });

  test('未知扩展名回退 png', () => {
    assert.strictEqual(mimeFromExt('xyz'), 'image/png');
  });
});

import * as assert from 'assert';
import { isTransientError, isValidResponse, vipPixelSize, buildRequestBody } from '../src/api';

suite('isTransientError', () => {

  test('HTTP 5xx 为瞬时错误', () => {
    assert.strictEqual(isTransientError('HTTP 500'), true);
    assert.strictEqual(isTransientError('HTTP 502'), true);
    assert.strictEqual(isTransientError('HTTP 503'), true);
  });

  test('HTTP 429 为瞬时错误', () => {
    assert.strictEqual(isTransientError('HTTP 429'), true);
  });

  test('fetch failed / abort 为瞬时错误', () => {
    assert.strictEqual(isTransientError('fetch failed'), true);
    assert.strictEqual(isTransientError('abort'), true);
    assert.strictEqual(isTransientError('AbortError'), true);
    assert.strictEqual(isTransientError('The operation was aborted'), true);
  });

  test('格式错误非瞬时', () => {
    assert.strictEqual(isTransientError('响应格式异常'), false);
    assert.strictEqual(isTransientError('Unexpected token'), false);
    assert.strictEqual(isTransientError(''), false);
  });

  test('HTTP 4xx 非 429 非瞬时', () => {
    assert.strictEqual(isTransientError('HTTP 400'), false);
    assert.strictEqual(isTransientError('HTTP 404'), false);
  });

});

suite('isValidResponse', () => {

  test('合法 succeeded 响应', () => {
    assert.strictEqual(isValidResponse({
      id: '123', status: 'succeeded', results: [{ url: 'http://example.com/a.png' }],
    }), true);
  });

  test('合法 running 响应', () => {
    assert.strictEqual(isValidResponse({
      id: '456', status: 'running', progress: 50,
    }), true);
  });

  test('缺少 id 不合法', () => {
    assert.strictEqual(isValidResponse({ status: 'succeeded' }), false);
  });

  test('状态不在枚举不合法', () => {
    assert.strictEqual(isValidResponse({ id: '1', status: 'unknown' }), false);
  });

  test('空对象不合法', () => {
    assert.strictEqual(isValidResponse({}), false);
  });

  test('null 不合法', () => {
    assert.strictEqual(isValidResponse(null), false);
  });

  test('results 格式错误不合法', () => {
    assert.strictEqual(isValidResponse({
      id: '1', status: 'succeeded', results: [{ notUrl: true }],
    }), false);
  });

});

suite('vipPixelSize', () => {

  test('1:1 + 1K → 1024x1024', () => {
    assert.strictEqual(vipPixelSize('1:1', '1K'), '1024x1024');
  });

  test('1:1 + 2K → 2048x2048', () => {
    assert.strictEqual(vipPixelSize('1:1', '2K'), '2048x2048');
  });

  test('16:9 + 1K → 1344x768', () => {
    assert.strictEqual(vipPixelSize('16:9', '1K'), '1344x768');
  });

  test('9:16 + 1K → 768x1344', () => {
    assert.strictEqual(vipPixelSize('9:16', '1K'), '768x1344');
  });

  test('3:4 + 1K → 864x1152', () => {
    assert.strictEqual(vipPixelSize('3:4', '1K'), '864x1152');
  });

  test('3:4 + 4K → 3456x4608', () => {
    assert.strictEqual(vipPixelSize('3:4', '4K'), '3456x4608');
  });

  test('未知组合回退默认值', () => {
    assert.strictEqual(vipPixelSize('99:99', '8K'), '864x1152');
  });

});

suite('buildRequestBody', () => {

  test('nano-banana 系列传 aspectRatio + imageSize', () => {
    const body = buildRequestBody('nano-banana-2', 'test prompt', [], '1:1', '2K');
    assert.strictEqual(body.aspectRatio, '1:1');
    assert.strictEqual(body.imageSize, '2K');
  });

  test('gpt-image-2 只传 aspectRatio', () => {
    const body = buildRequestBody('gpt-image-2', 'test', [], '16:9', '2K');
    assert.strictEqual(body.aspectRatio, '16:9');
    assert.strictEqual(body.imageSize, undefined);
  });

  test('gpt-image-2-vip 传像素值', () => {
    const body = buildRequestBody('gpt-image-2-vip', 'test', [], '1:1', '2K');
    assert.strictEqual(body.aspectRatio, '2048x2048');
    assert.strictEqual(body.imageSize, undefined);
  });

});

import * as assert from 'assert';
import type { JobState } from '../src/shared';

/** 聚合进度计算（纯函数，提取自任务逻辑便于测试） */
export function aggregateProgress(jobs: JobState[]): number {
  if (jobs.length === 0) return 0;
  const total = jobs.reduce((sum, j) => {
    if (j.status === 'succeeded' || j.status === 'failed' || j.status === 'violation') return sum + 100;
    if (j.status === 'running') return sum + (j.progress || 0);
    return sum; // submitting → 0
  }, 0);
  return Math.round(total / jobs.length);
}

suite('aggregateProgress', () => {

  test('全部 submitting → 0', () => {
    const jobs: JobState[] = [
      { index: 1, id: null, status: 'submitting', progress: 0, error: null, images: [] },
      { index: 2, id: null, status: 'submitting', progress: 0, error: null, images: [] },
    ];
    assert.strictEqual(aggregateProgress(jobs), 0);
  });

  test('混合态：1 succeeded + 1 submitting + 1 running(50%)', () => {
    const jobs: JobState[] = [
      { index: 1, id: 'a', status: 'succeeded', progress: 100, error: null, images: ['a.png'] },
      { index: 2, id: null, status: 'submitting', progress: 0, error: null, images: [] },
      { index: 3, id: 'b', status: 'running', progress: 50, error: null, images: [] },
    ];
    // (100 + 0 + 50) / 3 = 50
    assert.strictEqual(aggregateProgress(jobs), 50);
  });

  test('全部终结 → 100', () => {
    const jobs: JobState[] = [
      { index: 1, id: 'a', status: 'succeeded', progress: 100, error: null, images: ['a.png'] },
      { index: 2, id: 'b', status: 'failed', progress: 0, error: 'error', images: [] },
      { index: 3, id: 'c', status: 'violation', progress: 0, error: 'violation', images: [] },
    ];
    assert.strictEqual(aggregateProgress(jobs), 100);
  });

  test('空数组 → 0', () => {
    assert.strictEqual(aggregateProgress([]), 0);
  });

  test('running 带不同进度', () => {
    const jobs: JobState[] = [
      { index: 1, id: 'a', status: 'running', progress: 30, error: null, images: [] },
      { index: 2, id: 'b', status: 'running', progress: 70, error: null, images: [] },
    ];
    // (30 + 70) / 2 = 50
    assert.strictEqual(aggregateProgress(jobs), 50);
  });

});

import * as assert from 'assert';
import { buildRequestBody } from '../src/api';

suite('预览请求体构造', () => {

  test('构建请求体后可剔除 prompt 与 images', () => {
    const body = buildRequestBody('nano-banana-2', 'a prompt', ['data:image/png;base64,xxx'], '1:1', '1K');
    const params: Record<string, unknown> = {};
    for (const [k, v] of Object.entries(body)) {
      if (k !== 'prompt' && k !== 'images') {
        params[k] = v;
      }
    }

    // 应该没有 prompt 和 images
    assert.strictEqual('prompt' in params, false);
    assert.strictEqual('images' in params, false);
    // 应该有 model, aspectRatio, imageSize, replyType
    assert.strictEqual(params.model, 'nano-banana-2');
    assert.strictEqual(params.aspectRatio, '1:1');
    assert.strictEqual(params.imageSize, '1K');
    assert.strictEqual(params.replyType, 'async');
  });

  test('参考图概览格式', () => {
    const dataUri = 'data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAA';
    const preview = dataUri.slice(0, 48);
    const totalLen = dataUri.length;

    const line = `- image1: ${preview}…（${totalLen} 字符）`;
    assert.ok(line.startsWith('- image1: data:image/png;base64,'));
    assert.ok(line.includes('…'));
    assert.ok(line.includes('字符'));
  });

  test('无参考图输出"无参考图"', () => {
    const refImages: { index: number; dataUri: string; originalPath: string }[] = [];
    const text = refImages.length === 0 ? '无参考图' : '有参考图';
    assert.strictEqual(text, '无参考图');
  });

});

