import * as assert from 'assert';
import type { JobState } from '../src/shared';

/** 聚合进度计算（纯函数，提取自任务逻辑便于测试） */
export function aggregateProgress(jobs: JobState[]): number {
  if (jobs.length === 0) return 0;
  const total = jobs.reduce((sum, j) => {
    if (j.status === 'succeeded' || j.status === 'failed' || j.status === 'violation') return sum + 100;
    if (j.status === 'running') return sum + (j.progress || 0);
    return sum; // submitting → 0
  }, 0);
  return Math.round(total / jobs.length);
}

suite('aggregateProgress', () => {

  test('全部 submitting → 0', () => {
    const jobs: JobState[] = [
      { index: 1, id: null, status: 'submitting', progress: 0, error: null, images: [] },
      { index: 2, id: null, status: 'submitting', progress: 0, error: null, images: [] },
    ];
    assert.strictEqual(aggregateProgress(jobs), 0);
  });

  test('混合态：1 succeeded + 1 submitting + 1 running(50%)', () => {
    const jobs: JobState[] = [
      { index: 1, id: 'a', status: 'succeeded', progress: 100, error: null, images: ['a.png'] },
      { index: 2, id: null, status: 'submitting', progress: 0, error: null, images: [] },
      { index: 3, id: 'b', status: 'running', progress: 50, error: null, images: [] },
    ];
    // (100 + 0 + 50) / 3 = 50
    assert.strictEqual(aggregateProgress(jobs), 50);
  });

  test('全部终结 → 100', () => {
    const jobs: JobState[] = [
      { index: 1, id: 'a', status: 'succeeded', progress: 100, error: null, images: ['a.png'] },
      { index: 2, id: 'b', status: 'failed', progress: 0, error: 'error', images: [] },
      { index: 3, id: 'c', status: 'violation', progress: 0, error: 'violation', images: [] },
    ];
    assert.strictEqual(aggregateProgress(jobs), 100);
  });

  test('空数组 → 0', () => {
    assert.strictEqual(aggregateProgress([]), 0);
  });

  test('running 带不同进度', () => {
    const jobs: JobState[] = [
      { index: 1, id: 'a', status: 'running', progress: 30, error: null, images: [] },
      { index: 2, id: 'b', status: 'running', progress: 70, error: null, images: [] },
    ];
    // (30 + 70) / 2 = 50
    assert.strictEqual(aggregateProgress(jobs), 50);
  });

});

import * as assert from 'assert';
import { buildRequestBody } from '../src/api';

suite('预览请求体构造', () => {

  test('构建请求体后可剔除 prompt 与 images', () => {
    const body = buildRequestBody('nano-banana-2', 'a prompt', ['data:image/png;base64,xxx'], '1:1', '1K');
    const params: Record<string, unknown> = {};
    for (const [k, v] of Object.entries(body)) {
      if (k !== 'prompt' && k !== 'images') {
        params[k] = v;
      }
    }

    // 应该没有 prompt 和 images
    assert.strictEqual('prompt' in params, false);
    assert.strictEqual('images' in params, false);
    // 应该有 model, aspectRatio, imageSize, replyType
    assert.strictEqual(params.model, 'nano-banana-2');
    assert.strictEqual(params.aspectRatio, '1:1');
    assert.strictEqual(params.imageSize, '1K');
    assert.strictEqual(params.replyType, 'async');
  });

  test('参考图概览格式', () => {
    const dataUri = 'data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAA';
    const preview = dataUri.slice(0, 48);
    const totalLen = dataUri.length;

    const line = `- image1: ${preview}…（${totalLen} 字符）`;
    assert.ok(line.startsWith('- image1: data:image/png;base64,'));
    assert.ok(line.includes('…'));
    assert.ok(line.includes('字符'));
  });

  test('无参考图输出"无参考图"', () => {
    const refImages: { index: number; dataUri: string; originalPath: string }[] = [];
    const text = refImages.length === 0 ? '无参考图' : '有参考图';
    assert.strictEqual(text, '无参考图');
  });

});

